INSERT INTO watchlist VALUES('MRVL','','',NULL,0.0,-0.149999999999999994,NULL,NULL,'observe','sina_us',NULL,'USD',NULL,NULL,'2026-06-14T10:18:35','2026-06-14T10:18:35');
INSERT INTO research_thesis VALUES('COHR','AI光通信垂直整合龙头，从InP晶圆→EML激光芯片→光模块全栈自研。InP激光器是产业链真正瓶颈——InnoLight等竞争对手在模块层竞争，但在激光芯片层依赖COHR/LITE供应。','InP激光芯片垂直整合(唯一从衬底到模块全栈)；>50%高速EML通道份额；NVIDIA $20亿战略投资；InP产能翻倍建设中；1.6T首家OFC演示','["1.6T量产(H2 2026)——每模块激光含量翻倍", "NVIDIA $20亿投资+多年供应承诺", "InP产能翻倍——释放供应瓶颈", "混合转向DC&C(>75%收入)提升综合毛利率"]','中国竞争(InnoLight/翊捷)压低800G模块ASP；CPO长期可能改变插拔模块形态；库存周期导致收入波动；工业业务(SiC)拖累增长；~47x Forward P/E','BUY','2026-06-14T00:04:29');
INSERT INTO research_thesis VALUES('LITE','全球高速EML激光芯片#1(50-60%份额)，光通信产业链L5层核心光源。光模块厂商(InnoLight等)依赖LITE/COHR供应EML芯片。NVIDIA $20亿投资+产能售罄至2027。','EML激光芯片50-60%份额(双寡头:LITE+COHR)；30年+InP光子学研发积累；InnoLight等模块厂无法后向整合(InP外延需数十年经验)；EML供应缺口>30%至2027；NVIDIA $20亿投资','["Q4 FY26收入逼近$10亿(指引$9.6-10.1亿)", "1.6T量产(200G/lane EML首家量产认证)", "NVIDIA $20亿投资+美国新厂建设", "800G→1.6T激光含量翻倍", "AI光模块市场+57% YoY增长"]','COHR垂直整合可能自给EML(2-3年后)；Apple VCSEL合同流失给COHR；光通信历史性boom-bust周期；~45x Forward P/E已pricein大量增长；$640亿市值vs $30亿收入run-rate','BUY','2026-06-14T00:04:29');
INSERT INTO research_thesis VALUES('MU','全球HBM三巨头之一(#2,21%份额)，AI GPU必配高带宽内存。3家寡头垄断，新建DRAM厂需$150-250亿+4-5年——不可能有新进入者。美国唯一HBM生产商，CHIPS Act受益。','DRAM/HBM 40年+制造IP积累；HBM TSV堆叠技术；美国唯一HBM来源(国家安全价值)；三家寡头垄断+6年+进入壁垒；2026年HBM产能全部售罄','["B200/B300量产拉动HBM需求", "Vera Rubin HBM4分配", "DDR5价格回升(+60%)", "HBM份额从三星手中持续抢夺", "FY2026收入~$700亿(+193% YoY)"]','三星HBM良率恢复可能抢回份额；DRAM周期性(历史boom-bust)；中国CXMT增长压力；NAND低利润率拖累；股价已涨8倍','BUY','2026-06-14T00:04:29');
INSERT INTO research_thesis VALUES('LEU','美国唯一HALEU(高浓度低浓缩铀)生产商，西方世界仅此一家(另一家是俄罗斯Rosatom)。下一代SMR/先进反应堆物理上需要HALEU燃料。DOE $9亿扩产合同确认战略地位。','美国唯一HALEU许可生产商(AC-100M离心机技术)；西方唯一替代俄罗斯Rosatom的来源；DOE $9亿Piketon扩产合同；$38亿积压订单；新建浓缩厂需8-10年','["DOE $9亿扩产合同(2026.1)", "俄罗斯铀进口禁令(2028全面生效)", "大科技核电需求(微软/谷歌/亚马逊)", "新反应堆订单=锁定数十年HALEU需求"]','商业化HALEU规模生产要到~2034年；SMR商业化延迟(TerraPower推迟到2030)；57x P/E定价未来增长；DOE资金依赖政策风险；俄罗斯供应恢复则紧迫性降低','BUY','2026-06-14T00:04:29');
INSERT INTO research_thesis VALUES('PLAB','全球merchant光掩模双寡头(PLAB+Toppan)，光掩模是芯片制造不可跳过的物理步骤。但EUV掩模(最高价值段)被TSMC/Intel/Samsung captive掌控，PLAB无法进入。11.6x P/E深度折价。','Merchant光掩模双寡头(PLAB+Toppan各~20%总市场)；进入壁垒极高(掩模刻写机$5000万+/台+超净室+数十年工艺积累)；亚洲布局(台湾+韩国+中国厦门JV)','["中国成熟制程扩张驱动merchant掩模需求", "AI定制芯片设计增多=更多掩模组", "先进FPD/AMOLED掩模增长(+21% YTD)", "11.6x P/E vs同行18-35x的估值差"]','EUV掩模被captive垄断(PLAB无法进入最高价值段)；Q2 FY26营收miss+证券欺诈调查；客户集中(2家>10%)；TSMC/Intel/Samsung持续扩大captive产能','HOLD','2026-06-14T00:04:29');
INSERT INTO research_thesis VALUES('CAMT','HBM/CoWoS先进封装2D/3D检测专精厂商，纯正的先进封装检测受益标的。非经典瓶颈(KLA是检测霸主)，但HBM堆叠层数翻倍=检测步骤翻倍，TAM结构性增长。','先进封装检测性价比优势(比KLA便宜适合后端/OSAT)；AI增强视觉检测(Visual Layer收购)；2D+3D组合检测能力；台积电/英特尔/三星认证供应商','["$1.05亿+AI相关新订单(2026.6,交付2027)", "H2 2026指引>25%环比增长", "HBM4层数增加(8→12→16层)=检测步骤翻倍", "CoWoS/SoIC产能持续扩张"]','KLA进入先进封装检测(89.9%光学检测份额)；222x Trailing P/E估值极端；以色列地缘政治风险；31%空头比例','BUY','2026-06-14T00:04:29');
INSERT INTO research_thesis VALUES('HYNIX','全球HBM市场绝对霸主(58%份额)，NVIDIA公开确认的第一内存合作伙伴。72%营业利润率+HBM4首发量产+2026年全部产能售罄。系统内最高确信度瓶颈标的。','HBM 58%份额绝对领先；NVIDIA第一供应商(Jensen亲口确认)；HBM3/3E/4每一代首发量产；MR-MUF专有封装技术良率领先；iHBM下一代产品与NVIDIA共同设计','["US ADR上市(2026.8,~$140亿融资)", "Vera Rubin HBM4 60-70%分配", "NVIDIA多年战略协议(2026.6.7签署)", "产能三倍扩张计划", "iHBM下一代产品"]','三星HBM4认证通过(竞争加剧)；DRAM历史性周期风险；中国CXMT崛起(常规DRAM)；无锡工厂占50%产能(地缘风险)；股价12个月涨900%+','BUY','2026-06-14T00:04:29');
INSERT INTO research_thesis VALUES('CRDO','高速SerDes/AEC连接芯片龙头，AEC市占率~73%。AI数据中心机架内5-7m短距互联信号完整性层，每条400G/800G/1.6T以太网连接都需要SerDes信号调理。','n-1制程成本优势(成熟工艺实现前沿性能)；微软Azure大规模部署先发优势；DustPhotonics收购布局硅光子垂直栈；客户分散化进行中(最大客户从67%降至34%)','["1.6T交换机升级周期——AEC价值量翻倍", "DustPhotonics硅光子整合(对冲CPO风险)", "客户从1家分散至4家超大客户", "FY2027指引>80%收入增长"]','Marvell Golden Cable正面竞争(更大研发预算+捆绑销售能力)；估值30x+ P/S需高增长消化；AEC市场可能被CPO在3.2T时代侵蚀','HOLD','2026-06-14T00:04:29');
INSERT INTO research_thesis VALUES('AXTI','InP衬底双寡头之一(AXT~35%/住友~40%)，物理上不可替代(EML激光器必须在InP衬底上生长)。但中国子公司受出口管制影响+CEO大额套现$1710万+亏损状态+$64亿市值 vs $8800万收入——纯投机。','InP衬底双寡头(~35%份额)；VGF(垂直梯度凝固)专有晶体生长技术；InP价格因中国管控涨250%；多年客户认证周期','["800G→1.6T InP含量翻倍(8 vs 4 laser lanes)", "InP价格涨250%——ASP强烈顺风", "InP晶圆市场$1.98亿→$6.28亿(2030-35)", "Q1 2026收入+39% YoY"]','CEO套现$1710万(9笔,含单笔$690万)——公司这么小这金额很大；中国子公司(北京通美)受铟出口管控——直接影响出货；$64亿市值 vs $8800万收入+亏损=纯投机估值；住友(日本)不受中国管制——结构性更优','AVOID','2026-06-14T00:04:29');
INSERT INTO research_thesis VALUES('VICR','高密度功率模块专利持有者，正转型为''电力层高通''——通过VPD(垂直供电)专利向竞争者收取版税。NVIDIA未直接采用VICR组件(MPS/英飞凌为主供)，但VICR专利覆盖竞争者的垂直供电方案。','FPA(分解式电力架构)+VPD(垂直供电)专利覆盖面广；专利可能覆盖竞争者的多相垂直供电方案=收版税；2026.5签署新全包授权协议(未具名AI芯片厂商)；Q2指引从$1.26亿上调至$1.42亿(授权收入驱动)','["新专利授权协议(AI芯片厂商)提振收入", "VPD专利=即使竞争者赢socket也需付费", "FY2026指引~$5.7亿(+40% YoY)", "48V GPU供电标准化=整体TAM增长"]','NVIDIA未直接采用VICR组件(MPS 70-90% GB200份额)；100x+ Trailing P/E极端估值；CEO Vinciarelli 79岁无继任计划；2025年卖$1.11亿股票(仍持26%=~$25亿)；核心FPA专利2022-23年到期(续展专利延至2030s)','HOLD','2026-06-14T00:04:29');
INSERT INTO research_thesis VALUES('ADEA','先进封装DBI(Direct Bond Interconnect)混合键合专利收费站。半导体IP仅占6%收入($2600万)，但HBM4/3D chiplet采用混合键合将驱动TAM到2030年>$2亿。AMD诉讼和解+签署授权验证专利可执行性。','~11500项专利(含DBI基础专利,Ziptronix起源)；AMD诉讼和解+签约验证执行力；TSMC/ST/UMC/Canon/Sony已授权；混合键合覆盖Cu-Cu直接键合基础工艺','["AMD签约(Q1 2026)——打开逻辑芯片市场", "HBM4量产(2026-2027)——混合键合标准化", "逻辑chiplet厂商(Broadcom/Qualcomm)为下一波目标", "UMC扩展授权(2026.3)", "半导体IP订单翻倍+增长"]','半导体IP仅占6%收入——AI主题是小基数上的赌注；媒体IP面临剪线压力(收入下降风险)；专利可能被IPR挑战/无效化；TSMC/YMTC有自己的混合键合专利；CEO计划2026离职','HOLD','2026-06-14T00:04:29');
INSERT INTO research_thesis VALUES('WLDN','能源效率项目管理+市政工程服务公司，数据中心电网压力的间接受益者。非瓶颈——竞争性投标市场(ICF/CLEAResult/Guidehouse竞争)。真正的电网互联工程瓶颈在Burns & McDonnell/Black & Veatch等公司。','公用事业项目管理长期合同(3-5年)；加州能效市场深耕；20%+ Adj EBITDA利润率；$6.82亿收入(+20% YoY)增长稳健','["数据中心电网压力→公用事业需求管理预算增加", "AI驱动电力需求→能效项目TAM增长", "Q1 2026 EPS beat(+7.5%)"]','非瓶颈——竞争性投标市场(替代供应商多)；加州公用事业预算依赖监管政策；项目制收入波动；与AI关联为间接受益非直接链条；26x P/E已price-in增长','HOLD','2026-06-14T00:04:29');
INSERT INTO research_thesis VALUES('GSM','西方最大硅金属生产商，但硅金属是大宗商品非瓶颈。距芯片制造4步(硅金属→多晶硅→单晶硅锭→晶圆→芯片)，每步有不同供应商。半导体真正瓶颈在多晶硅/晶圆环节(信越/SUMCO)，不在冶金硅。','无——硅金属冶炼是19世纪化学，无IP壁垒；多家西方竞争者(Elkem/Wacker/Mississippi Silicon/REC)；中国控制75-80%产能随时可倾销','["美国关税保护可能收紧", "太阳能多晶硅需求增长", "2026年盈利恢复预期"]','大宗商品周期性(当前亏损EPS -$0.60)；中国随时可倾销；距AI 4步之遥——主题连接极其勉强；30x Forward P/E对于大宗商品公司不算便宜；FY2025营收指引下调','AVOID','2026-06-14T00:04:29');
INSERT INTO research_thesis VALUES('SMR','唯一获NRC设计认证的SMR(77 MWe VOYGR)，但旗舰项目CFPP已取消。零商业收入。罗马尼亚项目是make-or-break。NRC认证曾是护城河但TerraPower/GE-Hitachi正在追赶。$32-43亿市值的概念股。','唯一NRC设计认证(2020首批/2025升级77MWe)——5年领先但正在被追赶；Fluor背书(但Fluor也参与了失败的CFPP)；罗马尼亚Nuclearelectrica合作','["罗马尼亚462 MWe VOYGR-6项目推进", "Standard Power数据中心选用ENTRA1设计", "AI数据中心核电化叙事", "$10亿+现金提供生存跑道"]','CFPP旗舰项目取消(成本超支50%+)——信誉严重受损；Q1收入仅$57万(miss $700万估计)；TerraPower获NRC建设许可(2026.3)直接竞争；无运行中反应堆；概念股估值(80x trailing revenue)','HOLD','2026-06-14T00:04:29');
INSERT INTO research_thesis VALUES('NNE','微型核反应堆概念股，零收入，反应堆仅存在于纸面。HALEU运输业务收购提供近期小额收入但TAM微小。50+家美国公司开发先进反应堆——NNE无NRC认证、无技术壁垒、无客户。$12亿市值买一张彩票。','无——50+家公司竞争先进反应堆；NRC认证申请刚被接受审查(非批准)；无运行中反应堆；HALEU运输许可是唯一近期差异化但TAM极小','["NRC接受KRONOS MMR建设许可申请审查", "HALEU运输子公司收购(2026.6)", "AI数据中心核电需求叙事"]','零收入/$12亿市值——纯叙事定价；NRC完整许可需5-10年；50+竞争者(Oklo/Westinghouse/Radiant/X-energy)更有资金和技术；烧钱加速(Q2亏损+48%)；超大客户(微软/谷歌/亚马逊)选择成熟设计非初创','AVOID','2026-06-14T00:04:29');
INSERT INTO research_thesis VALUES('MX','韩国功率MOSFET/IGBT公司，已退出OLED DDIC业务。功率MOSFET完全商品化，无垄断/寡头地位，无AI产业链相关性。毛利率15.6%、持续亏损、$2.28亿市值。不属于瓶颈投资组合。','无——功率MOSFET是半导体最商品化的品类之一；英飞凌/安森美/ST/Vishay/数十家中国台湾厂商竞争；MX全球份额微乎其微','["OLED DDIC退出后纯功率半导体重组", "AI服务器PSU MOSFET市场($23亿)——但无差异化"]','持续亏损(EPS -$0.11)；毛利率15.6%(vs英飞凌45%)——无定价权；中国ASP侵蚀；$4230万债务2027.3到期；$5000万Shelf Registration=潜在稀释；与AI无实质关联','AVOID','2026-06-14T00:04:29');
INSERT INTO research_thesis VALUES('ALAB','PCIe/CXL retimer物理必需芯片龙头(60-70%AI服务器份额)。Gen5/Gen6速度下信号衰减不可避免——retimer是物理法则决定的瓶颈。76%毛利率。但$630亿市值/125x Fwd P/E已完全price-in。','PCIe retimer 60-70%份额先发优势；Gen5/Gen6首家量产认证；认证后转换成本高(12-18月重新认证)；Cosmos平台软件/固件生态锁定；多协议覆盖(PCIe+CXL+Ethernet+UALink)','["Scorpio以太网交换机H2 2026量产(TAM $200亿 by 2030)", "PCIe Gen6 retimer首家量产", "CXL内存扩展(微软Azure已部署Leo)", "FY2026E收入~$15.5亿(+82% YoY)"]','Broadcom Gen6 retimer正面竞争(可捆绑网络+retimer+定制ASIC)；Marvell Alaska P进入(3方寡头化)；NVIDIA NVLink/NVSwitch绕过PCIe减少retimer用量；$630亿市值/125x Fwd P/E——极端估值；Scorpio进入Broadcom网络腹地风险大','HOLD','2026-06-14T00:29:09');
INSERT INTO research_thesis VALUES('UCTT','半导体设备气体/流体交付子系统双寡头(与ICHR)。Lam Research和Applied Materials最大外包子系统供应商。认证锁定12-18月转换成本。但16.5%毛利率=build-to-print供应商，非真正定价权瓶颈。','气体/流体子系统双寡头(UCTT+ICHR)；OEM认证锁定(换供应商需12-18月重新认证+污染风险)；Products+Services双模式(设备OEM+直接服务晶圆厂)；规模优势(最大外包供应商)','["WFE支出上行周期($1450亿 2026→$1560亿 2027)", "营业利润率从负转正(FY2025 -5.28%→FY2026恢复)", "管理层$40亿收入路线图", "半导体设备周期复苏"]','极端周期性(FY2025营业利润率-5.28%)；客户集中(Lam+AMAT可能>60%收入)；16.5%毛利率=无定价权/build-to-print；ICHR直接竞争；估值已涨230% YTD','HOLD','2026-06-14T00:29:09');
INSERT INTO company_profiles VALUES('COHR','Coherent Corp(原II-VI+Coherent合并)是全球最垂直整合的AI光通信公司。数据通信与通信(DC&C)占收入~70%，工业占~30%。FY2026E收入~$67亿。NVIDIA $20亿战略投资背书。从InP晶圆生长→外延→激光芯片→封装→光模块，全栈自研。','["800G/1.6T光收发器(DC&C主力)", "EML/DFB激光芯片 — >50%高速EML通道份额", "InP晶圆 — 自研衬底材料", "SiC碳化硅衬底(EV功率)", "ROADM/WSS(网络光交换)", "工业激光器"]','光模块层: 与InnoLight(中国第一)竞争，800G正在商品化。但激光芯片层: COHR+LITE控制行业大部分EML供应——InnoLight等依赖外购激光芯片。COHR的结构性优势是垂直整合——无论谁赢模块市场，COHR在芯片层都赢。','1. InP垂直整合——从衬底到模块全栈，业内唯一 2. >50%高速EML通道份额 3. 1.6T OFC 2025首家演示 4. NVIDIA $20亿投资锁定供应关系 5. InP产能翻倍(6英寸产线扩张)','["微软/谷歌/Meta/亚马逊(超大规模客户)", "NVIDIA(战略投资方+大客户)", "前3-4客户可能>50% DC&C收入"]','["高度垂直整合，自研InP晶圆和激光芯片", "外部依赖主要在代工/封测环节"]','1. InnoLight/翊捷800G价格战压缩模块毛利 2. CPO(共封装光学)长期改变模块形态——但COHR激光芯片不受影响 3. 超大客户采购周期波动(库存消化期) 4. 工业/SiC业务拖累整体增速(~30%收入增长缓慢) 5. ~47x Forward P/E需持续高增长','AI光模块市场2026年$260亿(TrendForce,+57% YoY)。1.6T每模块激光含量翻倍，进一步扩大可寻址市场。','{"item1": "Item 1. Business - General Description of Business of this Annual Report on Form 10-K for further information. Trends and Other Matters Affecting our Business Industry Conditions Throughout fiscal 2025, we experienced stronger demand in our Communications market. The increase in the number of hyperscale and other cloud customers building AI datacenters and in the number and size of their AI datacenter buildouts drove demand for our datacenter transceivers. Strong demand for our new ZR/ZR+ transceiver products along with growing demand for traditional telecom transport products drove increased volumes for our telecom and other communications solutions. Additionally, within our Industrial market, we were able to grow our industrial lasers products and services revenue in the face of relatively weak overall industrial end demand. Our revenue growth in these portions of the Industrial market is a result of our focus on higher demand applications within the Industrial market, including display and semiconductor capital equipment. Restructuring Plans 2023 Plan On May 23, 2023, the Board of Directors approved the 2023 Plan which includes site consolidations, facilities moves and closures, as well as the relocation and requalification of certain manufacturing facilities. These restructuring actions were intended to realign our cost structure as part of a transformation to a simpler, more streamlined, resilient and sustainable business model. In fiscal 2025, these activities resulted in charges of $53 million, primarily for impairment losses associated with the sale of our Newton Aycliffe business, impairment of right-of-use (“ROU”) assets, employee termination costs, site move costs and accelerated depreciation. In fiscal 2024, these activities resulted in charges of $27 million, primarily for accelerated depreciation, the write-off of property and equipment, and site move costs. In fiscal 2023, these activities resulted in $119 million of charges primarily for employee termination costs, and the write-off of property and equipment, net of $65 million from reimbursement arrangements. See Note 20. Restructuring Plans to the Company’s Consolidated Financial Statements included in Item 8 of this Annual Report on Form 10-K for further information. 2025 Plan Commencing in the quarter ended March 31, 2025, and as part of the ongoing strategic review of the Company’s business, the Company’s management approved the 2025 Plan to take a number of restructuring actions, including site consolidations, facilities moves and closures, workforce reductions, contract terminations, and certain other associated cost reductions. In fiscal 2025, these activities resulted in $107 million of charges primarily for the write-off of property and equipment and ROU assets, employee and contract termination costs. We expect the restructuring actions to be substantially completed by the 35 end of fiscal 2026. However, the actual timing and costs associated with these restructuring actions may differ from our current expectations and estimates and such differences may be material. Synergy and Site Consolidation Plan On May 20, 2023, the Company announced that it had accelerated some of the actions planned as part of its multi-year synergy and site consolidation efforts following the acquisition of Coherent, Inc., including site consolidations and relocations to lower cost sites. These relocations and other actions resulted in the Company achieving its previously announced $250 million synergy plan, which included savings from supply chain management, internal supply of enabling materials and components, operational efficiencies in all functions due to scale, global functional model efficiencies and consolidation of corporate costs. In fiscal 2025, the acceleration of these activities resulted in $17 million of charges primarily for overlapping labor related to transition of manufacturing operations to other sites, shut down costs and employee termination costs. In fiscal 2024, the acceleration of these activities resulted in $40 million of charges primarily for overlapping labor related to transition of manufacturing operations to other sites, shut down costs for sites being exited, accelerated depreciation and employee termination costs. In fiscal 2023, the acceleration of these activities resulted in $20 million in charges primarily for employee termination costs, the write-off of inventory for products that have been exited and shut down costs. Impairment of Assets Held-for-Sale In the fourth quarter of fiscal 2025, management entered into non-binding agreements to sell several entities. As a result of classifying these entities as held-for-sale, we recorded non-cash impairment charges of $85 million to Impairment of assets held-for-sale in our Consolidated Statements of Earnings (Loss) in the fourth quarter of fiscal 2025 to reduce our carrying value in these entities to fair value. See Note 21. Assets Held-for-Sale to the Company’s Consolid", "item1a": "Item 1A. Risk Factors – Risks Related to Our Business, Operations, and Industry – Cybersecurity attacks and incidents and other vulnerabilities could subject us to costly damages, claims and expenses, harm to our reputation or competitive position, or disrupt our operations and business.” Governance One of the key functions of our Board of Directors is informed oversight of our risk management process, including risks from cyber security threats. Our Board of Directors is responsible for monitoring and assessing strategic risk exposure, and our executive officers are responsible for the day-to-day management of the material risks we face. Our Board of Directors administers its cybersecurity risk oversight function through the Nominating and Corporate Governance (“NCG”) Committee. The NCG Committee is briefed quarterly by management on, among other things, our company’s cybersecurity risks and activities, including any recent cybersecurity incidents and related responses, cybersecurity systems testing, activities of third parties, and the like. The NCG Committee provides regular updates to the Board of Directors on such reports. Our Chief Information Officer and Global Head of Cybersecurity have combined relevant experience of more than 45 years, including over 20 years in cybersecurity , and they oversee our cyber security policies and processes, including those described in “Risk Management and Strategy” above. Our Global Head of Cybersecurity monitors and keeps informed about prevention, detection, mitigation, and remediation efforts through regular communication and reporting from our cybersecurity team, and through the use of technological tools and software and results from third party assessments. 31 Item 2. PROPERTIES Information regarding our principal U.S. properties at June 30, 2025, is set forth below: Location Primary Use(s) Primary Business Segment(s) Approximate Square Footage Ownership Sherman, TX Manufacturing Materials 700,000 Owned Easton, PA Manufacturing and Research and Development Materials 281,000 Leased Saxonburg, PA Manufacturing and Research and Development Materials 235,000 Owned and Leased Santa Clara, CA Manufacturing, Research and Development and Administration Lasers 199,993 Owned Newark, DE Manufacturing and Research and Development Materials 135,000 Leased Fremont, CA Manufacturing and Research and Development Materials 121,556 Leased Murrieta, CA Manufacturing and Research and Development Materials 108,000 Leased Information regarding our principal foreign properties at June 30, 2025, is set forth below: Location Primary Use(s) Primary Business Segment(s) Approximate Square Footage Ownership China Manufacturing, Research and Development, and Distribution Materials and Networking 3,310,650 Owned and Leased Germany Manufacturing, Research and Development Lasers 892,000 Owned and Leased Malaysia Manufacturing, Research and Development Networking 889,205 Owned Vietnam Manufacturing Materials and Networking 719,000 Owned and Leased Philippines Manufacturing Materials 426,240 Leased United Kingdom Manufacturing, Research and Development Lasers and Networking 187,568 Owned and Leased Germany Manufacturing and Distribution Materials and Networking 137,700 Owned and Leased Finland Manufacturing Lasers 122,106 Leased Switzerland Manufacturing, Research and Development, and Distribution Materials 112,000 Leased The square footage listed for each of the above properties represents facility square footage, except in the case of the Philippines location, which includes land. Item 3. LEGAL PROCEEDINGS The Company and its subsidiaries are involved in various claims and lawsuits incidental to its business. The resolution of each of these matters is subject to various uncertainties, and it is possible that these matters may be resolved unfavorably to the Company. Management believes, after consulting with legal counsel, that the ultimate liabilities, if any, resulting from such legal proceedings will not materially affect the Company’s financial condition, liquidity, or results of operations. Item 4. MINE SAFETY DISCLOSURES Not applicable. 32 PART II Item 5. MARKET FOR REGISTRANT’S COMMON EQUITY, RELATED STOCKHOLDER MATTERS AND ISSUER PURCHASES OF EQUITY SECURITIES The Company’s common stock is traded on the New York Stock Exchange (the “NYSE”) under the symbol “COHR”, beginning February 23, 2023 when the Company voluntarily transferred the listing of its common stock from the NASDAQ Global Select Market to the NYSE. As of August 11, 2025, there were approximately 790 holders of record of our common stock. The Company historically has not paid cash dividends on its common stock and does not presently anticipate paying cash dividends on its common stock in the future. Dividends on the Company’s Series A Mandatory Convertible Preferred Stock were payable on a cumulative basis when, as and if declared by our Board of Directors, or an authorized committee of our Board of Directors, at an annual ", "item7": "Item 7. MANAGEMENT’S DISCUSSION AND ANALYSIS OF FINANCIAL CONDITION AND RESULTS OF OPERATIONS Management’s Discussion and Analysis of Financial Condition and Results of Operations (MD&A) is designed to provide a reader of Coherent’s financial statements with a narrative from the perspective of management. The following discussion and analysis of our financial condition and results of operations should be read in conjunction with our Consolidated Financial Statements and related notes included under Item 8 of this annual report. Coherent’s MD&A is presented in the following sections: • Overview • Trends and Other Matters Affecting our Business • Critical Accounting Policies and Estimates • Fiscal Year 2025 Compared to Fiscal Year 2024 • Fiscal Year 2024 Compared to Fiscal Year 2023 • Liquidity and Capital Resources • Off Balance Sheet Arrangements Forward-looking statements in Item 7 may involve risks and uncertainties that could cause results to differ materially from those projected (refer to Item 1A for discussion of these risks and uncertainties). Overview For an overview of our business, see Part I - Item 1. Business - General Description of Business of this Annual Report on Form 10-K for further information. Trends and Other Matters Affecting our Business Industry Conditions Throughout fiscal 2025, we experienced stronger demand in our Communications market. The increase in the number of hyperscale and other cloud customers building AI datacenters and in the number and size of their AI datacenter buildouts drove demand for our datacenter transceivers. Strong demand for our new ZR/ZR+ transceiver products along with growing demand for traditional telecom transport products drove increased volumes for our telecom and other communications solutions. Additionally, within our Industrial market, we were able to grow our industrial lasers products and services revenue in the face of relatively weak overall industrial end demand. Our revenue growth in these portions of the Industrial market is a result of our focus on higher demand applications within the Industrial market, including display and semiconductor capital equipment. Restructuring Plans 2023 Plan On May 23, 2023, the Board of Directors approved the 2023 Plan which includes site consolidations, facilities moves and closures, as well as the relocation and requalification of certain manufacturing facilities. These restructuring actions were intended to realign our cost structure as part of a transformation to a simpler, more streamlined, resilient and sustainable business model. In fiscal 2025, these activities resulted in charges of $53 million, primarily for impairment losses associated with the sale of our Newton Aycliffe business, impairment of right-of-use (“ROU”) assets, employee termination costs, site move costs and accelerated depreciation. In fiscal 2024, these activities resulted in charges of $27 million, primarily for accelerated depreciation, the write-off of property and equipment, and site move costs. In fiscal 2023, these activities resulted in $119 million of charges primarily for employee termination costs, and the write-off of property and equipment, net of $65 million from reimbursement arrangements. See Note 20. Restructuring Plans to the Company’s Consolidated Financial Statements included in Item 8 of this Annual Report on Form 10-K for further information. 2025 Plan Commencing in the quarter ended March 31, 2025, and as part of the ongoing strategic review of the Company’s business, the Company’s management approved the 2025 Plan to take a number of restructuring actions, including site consolidations, facilities moves and closures, workforce reductions, contract terminations, and certain other associated cost reductions. In fiscal 2025, these activities resulted in $107 million of charges primarily for the write-off of property and equipment and ROU assets, employee and contract termination costs. We expect the restructuring actions to be substantially completed by the 35 end of fiscal 2026. However, the actual timing and costs associated with these restructuring actions may differ from our current expectations and estimates and such differences may be material. Synergy and Site Consolidation Plan On May 20, 2023, the Company announced that it had accelerated some of the actions planned as part of its multi-year synergy and site consolidation efforts following the acquisition of Coherent, Inc., including site consolidations and relocations to lower cost sites. These relocations and other actions resulted in the Company achieving its previously announced $250 million synergy plan, which included savings from supply chain management, internal supply of enabling materials and components, operational efficiencies in all functions due to scale, global functional model efficiencies and consolidation of corporate costs. In fiscal 2025, the acceleration of these activities resulted in $17 million of charges primarily for overlapping l"}','deep_research','2025-08-15','2026-06-14T00:04:29');
INSERT INTO company_profiles VALUES('LEU','Centrus Energy是美国唯一获许可的HALEU(高浓度低浓缩铀,5-19.75%)生产商。两个业务: LEU(铀浓缩服务+SWU交易,~75%收入)和技术方案(DOE HALEU合同+政府工程,~25%)。FY2025收入$4.49亿，积压订单$38亿。股价从52周高点$464跌至~$158(-65%)。','["HALEU浓缩铀 — 下一代核反应堆(SMR/先进堆)必需燃料", "LEU交易 — 标准低浓缩铀购销", "AC-100M离心机 — 美国自主开发的浓缩技术", "DOE技术服务 — Piketon设施运维+浓缩工程"]','全球HALEU供应: Rosatom(俄罗斯,唯一商业规模)→ Centrus(美国,示范规模)→ 中国(有能力但不出口)。西方别无选择。2025年中已向DOE交付900kg HALEU。竞争者: Urenco可能进入HALEU但尚未生产。','1. AC-100M离心机——美国自主浓缩技术 2. Piketon设施——唯一获NRC许可的HALEU生产场地 3. DOE $9亿扩产合同锁定产能 4. 900kg HALEU已交付——技术验证完成 5. 新建浓缩厂需8-10年——进入壁垒极高','["美国能源部(DOE) — 主要客户", "公用事业公司(LEU交易)", "未来: TerraPower/X-energy/Kairos等先进反应堆开发商"]','["离心机制造: Oak Ridge, TN(2025.12开始)", "铀原料: 全球市场采购", "设施: Piketon, OH"]','1. 商业规模HALEU生产要到~2034年——现在到盈利还有很长的桥 2. SMR商业化不断延迟(NuScale CFPP取消/TerraPower推到2030) 3. 57x P/E定价了大量未实现的未来增长 4. DOE资金依赖——政策风险(政府换届) 5. 若俄罗斯供应恢复则紧迫性大幅降低','浓缩铀市场2025年$84亿→2034年$147亿(CAGR 6.4%)。HALEU细分市场随SMR商业化从零增长到数十亿。','{"item1": "Item 1 - Business , for additional information. Market Conditions and Outlook The global nuclear industry outlook began to improve after many years of decline and stagnation. The development of advanced small and large-scale reactors, the innovation of advanced fuel types, and the commitment of nations to begin deploying nuclear power or to increase the share of nuclear power in their nations has created optimism in the market. Part of the momentum has resulted from efforts to lower greenhouse gas emissions to combat climate change and improve health and safety. According to the WNA, as of January 2026, there were approximately 70 reactors under construction worldwide, approximately one-half of which are in China. The United States, with over 90 operating reactors, remains the world’s largest market for nuclear fuel. The nuclear industry in the United States, Japan, and Europe faces headwinds as well as opportunities. In the United States, the industry has been under pressure from the expansion of subsidized renewable energy as well as relatively low-cost natural gas resources in recent years. Eight U.S. reactors have prematurely shut down in the past ten years and others could shut down in the next few years. At the same time, construction was completed and commercial operations began in the second quarter of 2024 on one large reactor and two formerly shutdown reactors have plans to restart. 60 The IEA projects that global nuclear energy generation will grow substantially in the next three decades. In the IEA’s 2025 World Energy Outlook , nuclear generation is forecasted to grow 38% by 2035 and 62% by 2040 under the “Stated Policies” scenario. In the “Net Zero Emissions by 2050” scenario, nuclear generation would grow 70% by 2035 and more than double by 2040. As a consequence of the March 2011 earthquake and tsunami in Japan, over 60 reactors in Japan and Germany were taken offline, and other countries curtailed or slowed their construction of new reactors or accelerated the retirement of existing plants. In Japan, 15 reactors have restarted and an additional 10 reactors are in the process of restart approval. As a result of the war in Ukraine, the EU is encouraging its member countries to reconsider the planned early retirement of existing plants in order to reduce reliance on Russian gas imports. In October 2020, the DOC reached an agreement with the Russian Federation on an extension of the RSA, a trade agreement which allows for Russian-origin nuclear fuel to be exported to the United States in limited quantities. The two parties agreed to extend the agreement through 2040 and to set aside a significant portion of the annual quota for Centrus’ shipments to the United States through 2028 to execute our long-term TENEX Supply Contract with TENEX. This outcome allows for sufficient quota for Centrus to continue serving its utility customers and support its investments in building new capacity. Use of this quota is subject to compliance with limitations under the RSA. These limitations include a requirement that we return natural uranium to TENEX for the LEU we receive under the TENEX Supply Contract at approximately the same time that we deliver the LEU to our customers. Our ability to meet this requirement depends on the capacity or willingness of the facilities where natural uranium is supplied to us by customers, to allow us to deliver this natural uranium to TENEX. We were notified by one facility that it will no longer receive natural uranium for TENEX. As a result, we will need to rely to a greater extent on deliveries at other processors or explore other options in order to comply with the RSA’s natural uranium delivery requirement. 61 The war in Ukraine has escalated tensions between Russia and the international community. As a result, the United States and other countries imposed, including through the U.S.’s enactment of the Import Ban Act discussed below, and may continue imposing, additional sanctions, tariffs, and export controls against certain Russian products, services, organizations and/or individuals, and Russia passed the Russian Decree as discussed below. Such additional restrictions, and any Russian response thereto, could affect our ability to purchase, take delivery of, transport, or re-sell Russian uranium enrichment, engage in transactions with TENEX, or implement the TENEX Supply Contract, which would have a negative material impact on our business. Further, tariffs or sanctions by the United States, Russia or other countries may impact our ability and the cost to transport, export, import, take delivery, or make payments related to the LEU we purchase and may require us to increase purchases from non-Russian sources to the extent available. For example, due to restrictions imposed by Canada on the ability of Canadian persons and entities to provide ocean transportation services to Russia, a permit is required for our shipper, a Canadian company, to transport the LEU that we proc", "item1a": "Item 1A. Risk Factors The following discussion sets forth the material risk factors that could affect our financial condition and operations. Such risks, which could negatively affect our Consolidated Financial Statements, fall primarily under the categories listed below. Readers should not consider any descriptions to be a complete set of all potential risks that could affect us. Risks related to the war in Ukraine factors primarily include: • the current war in Ukraine and related international sanctions and restrictions; • market and supply chain complications arising from the Import Ban Act, and the Russian Decree; a nd • financial losses we incur in connection with (i) the impact of government sanctions and tariffs imposed in response to the invasion of Ukraine and/or (ii) disputes with our counterparties arising from such sanctions or mitigation efforts. Risks related to economic and industry factors primarily include: • the financial difficulties experienced by, and operating conditions of, our customers and suppliers; • epidemics and other health related issues; and • price volatility associated with the procurement of SWU and uranium, which may be exacerbated by any U.S. or foreign government sanctions or other actions. Risks related to operational factors primarily include: • our inability to successfully perform our U.S. government contracts, including any task orders we may be awarded; • our ability to successfully implement our planned expansion projects in Piketon, Ohio and Oak Ridge, Tennessee; • disruptions arising from the Import Ban Act or the Russian Decree restricting imports, exports or sales of SWU or uranium that we buy from our Russian supplier and our other sources of supply; • the inability to sell all of the LEU we are required to purchase under supply agreements for prices that cover our costs. • tariffs and other changes in internal trade policy; • significant competition from foreign governments, and limitations on our ability to compete in foreign markets; • our dependence on our largest customers and suppliers; and • lack of assurance that we will be awarded additional task orders under any of our IDIQ contracts and, if awarded, the nature, timing and amount of the task orders that may be issued under an award is uncertain. Risks related to financial factors primarily include: • significant long-term liabilities, including our 0% Convertible Notes and our 2.25% Convertible Notes; • material postretirement health and life benefit obligations; • our revenues and operating results may fluctuate significantly from quarter to quarter and year to year; • possible impairment loss related to our intangible assets; • dependency on intercompany support from Enrichment Corp.; • a small number of holders of our Class A Common Stock may exert significant influence over the direction of the Company; and • limited ability to utilize our NOL carryforwards to offset future taxable income. 26 Risks related to legal and compliance factors primarily include: • our operations being out of compliance with applicable regulations, including those issued by the U.S. government, including the NRC and the DOE, and the States of Ohio and Tennessee; • uncertainty arising from U.S. government administration reliance on executive orders in lieu of federal legislation to implement regulatory policy and objectives; • liability related to our use, transportation and disposal of toxic, hazardous and/or radioactive materials, including liability that may arise without regard to fault or negligence; and • our certificate of incorporation gives us certain rights with respect to equity securities held (beneficially or of record) by foreign persons. Risks related to general factors primarily include: • failures to protect classified or other sensitive information, or security breaches of IT systems could result in significant liability; • artificial intelligence risks and challenges that can impact our business, including regulatory risks and operational risks if artificial intelligence is integrated into our operations and cybersecurity risks in the event that artificial intelligence is used by a threat actor in cybersecurity incident; • the inability to attract and retain key personnel; • the potential for the DOE to seek to terminate or exercise its remedies under the 2002 DOE-USEC Agreement and our other agreements with the DOE, or to require modifications to such agreements; • government reviews or audits can lead to withholding or delay of payments to us, non-receipt of award fees, legal actions, fines, penalties and liabilities, and other remedies against us; • our U.S. government contracts and subcontracts are dependent on continued U.S. government funding and government appropriations, which may not be made on a timely basis or at all; • changes to, or termination of, any agreements with the U.S. government, or deterioration in our relationship with the U.S. government; and • the ability to adapt to a rapi", "item7": "Item 7. Management’s Discussion and Analysis of Financial Condition and Results of Operations The following discussion should be read in conjunction with, and is qualified in its entirety by reference to, the Consolidated Financial Statements and related notes appearing elsewhere in this report. This discussion contains forward-looking statements that involve risks and uncertainties. Actual results could differ significantly from the results discussed in the forward-looking statements particularly in light of the economic, social and market uncertainty created by, among other things, the war in Ukraine. See “Forward-Looking Statements” at the beginning of this Annual Report on Form 10-K. Overview Centrus Energy Corp., a Delaware corporation, is a trusted supplier of nuclear fuel components for the nuclear power industry, which provides a reliable source of carbon-free energy and provides enrichment and technical services for public and private customers. References to “Centrus”, the “Company”, “our”, or “we” include Centrus Energy Corp. and its wholly-owned subsidiaries as well as the predecessor to Centrus, unless the context indicates otherwise. Centrus operates two business segments: (a) LEU, which supplies various components of nuclear fuel to commercial customers from our global network of suppliers, and (b) Technical Solutions, which provides advanced uranium enrichment for the nuclear industry and the U.S. government and advanced manufacturing and other technical services to government and private sector customers. Published spot price indicators for SWU reached historic highs in April 2009 at $163 per SWU. In the years following the 2011 Fukushima accident in Japan, spot prices declined more than 75%, bottoming out in August 2018 at $34 per SWU. This was followed by a period of price increases, which reached $195 per SWU by December 31, 2024. In 2025, spot prices continued to increase, reaching $200 per SWU by December 31, 2025, which surpasses the previous historic high. This represents an increase of 3% since the beginning of the year and 488% over the 2018 historic low. This surge in the SWU spot price beginning in 2022 has been driven primarily by uncertainty created as a result of Russia’s invasion of Ukraine, coupled with growing interest in nuclear power as a source of secure and carbon-free energy. The contemplation of the imposition of tariffs on LEU, if ultimately imposed, may put additional upward pressure on the price of SWU. For further details, refer to Part I, Item 1A, Risk Factors - The current war in Ukraine and related international or U.S. sanctions, tariffs and restrictions on trade, and the Russian response thereto, could have a material adverse impact on our business, results of operations, and financial condition. When Russian supply is included, the uranium enrichment segment of the global nuclear fuel market is oversupplied, but without Russian supply, the global market for uranium enrichment would be undersupplied. Further, it is not clear that there are sufficient inventories of enriched uranium in the United States to compensate for a loss of Russian supply, absent new capacity that will take a number of years to deploy. Changes in the supply-demand balance and in the competitive landscape arising from the war in Ukraine or the imposition of tariffs may affect pricing trends, change customer spending patterns, and create uncertainty in the uranium market. At the same time, uncertainty remains about future demand for nuclear power generation. To address such changes and uncertainty, we continue to evaluate opportunities to grow our business organically or through acquisitions and other strategic transactions. The Company’s work on HALEU began under the HALEU Demonstration Contract, executed with the DOE in 2019, to construct a cascade of 16 AC100M centrifuges in Piketon, Ohio to demonstrate HALEU production. The DOE has funded the HALEU Demonstration Contract up to $173.0 million with a period of performance that ended November 30, 2022. 55 On November 10, 2022, the DOE awarded the HALEU Operation Contract to the Company with a base contract value of approximately $150.0 million in two phases through 2024. Phase 1 included an approximately $30.0 million cost-share contribution from Centrus matched by approximately $30.0 million from the DOE to complete construction of the cascade, begin operations and produce the initial 20 kilograms of HALEU UF 6 . On November 7, 2023, the Company made its first contractual delivery of HALEU to the DOE, completing Phase 1 of the HALEU Operation Contract. During November 2023, the Company transitioned to Phase 2 of the HALEU Operation Contract, which included production of 900 kilograms of HALEU UF 6 for one production year, as well as continued operations and maintenance of the cascade. Phase 2 included an initial contract value of approximately $90.0 million and compensation on a cost-plus-incentive-fee-basis. The DOE owns the HALEU prod"}','deep_research','2026-02-11','2026-06-14T00:04:29');
INSERT INTO company_profiles VALUES('LITE','Lumentum Holdings是全球#1高速EML(电吸收调制激光器)芯片供应商，50-60%市场份额。EML是每颗800G/1.6T光模块的核心光源——没有EML就没有光模块。Q3 FY26收入$8.08亿(+90% YoY)。NVIDIA $20亿战略投资。市值~$640亿。','["EML激光芯片(100G/200G per lane) — 主营增长引擎", "CW激光器 — 硅光子方案光源", "ROADM WSS — 电信网络光交换", "3D感知VCSEL — Apple FaceID(份额被COHR蚕食)", "工业/商业激光器"]','EML双寡头: Lumentum 50-60% + Coherent ~30% + 三菱电机~10%。InnoLight等模块厂从LITE/COHR采购EML芯片——LITE在上游组件层是不可替代的。Coherent既是竞争者也是客户(向LITE采购EML)。','1. 30年+InP光子学研发(JDSU传承) 2. InP外延生长+EML制造——亚纳米精度工艺 3. 200G/lane EML首家量产认证(1.6T就绪) 4. 日本EML工厂扩产50%(2026.12完成) 5. EML供应缺口>30%至2027——结构性短缺','["光模块厂商: InnoLight/Coherent/翊捷(客户兼竞争者)", "NVIDIA(战略投资方)", "Ciena/Nokia/Cisco(ROADM WSS)"]','["自有InP晶圆厂(美国/日本)", "InP衬底: AXT/Sumitomo", "开始建设CW激光器内部产能"]','1. Coherent垂直整合可能减少对LITE EML的采购(2-3年) 2. Apple VCSEL合同流失给Coherent(2025.8) 3. 光通信boom-bust历史周期 4. ~45x Forward P/E定价完美执行 5. NVIDIA投资锁定也是集中度风险','AI光模块市场2026年$260亿(+57% YoY,TrendForce)。800G→1.6T每模块激光含量翻倍。EML是光模块BOM中最高价值组件。','{"item1": "ITEM 1. BUSINESS General Overview Lumentum Holdings Inc. (“we,” “us,” “our”, “Lumentum” or the “Company”) is a leading provider of optical and photonic products and is recognized as an industry leader based on revenue and market share. Our products are essential to a range of cloud, artificial intelligence and machine learning (“AI/ML”), telecommunications, consumer, and industrial end-market applications. We operate in two end-market focused reportable segments, Cloud & Networking and Industrial Tech. Our Cloud & Networking products comprise a comprehensive portfolio of optical and photonic chips, components, modules, and subsystems supplied to cloud data center operators, AI/ML infrastructure providers, and network equipment manufacturer customers who are building cloud data center and network infrastructures. Our products enable high-capacity optical links for cloud computing, AI/ML workloads, and data center interconnect (“DCI”) applications, as well as for communications service provider networks. Our offerings support access (local), metro (intracity), long-haul (intercity and global), and submarine (undersea) network infrastructure. Additionally, our Cloud & Networking products serve enterprise network infrastructure needs, including storage area networks (“SANs”), local area networks (“LANs”), and wide area networks (“WANs”). Demand for our products is fueled by the ongoing expansion of network capacity required to support cloud and services, AI/ML processing, streaming video, video conferencing, wireless and mobile connectivity, and the internet of things (“IoT”). Our Industrial Tech products include short-pulse solid-state lasers, kilowatt-class fiber lasers, diode lasers, and gas lasers, serving a wide range of end-markets applications. In the consumer market, our laser light sources are integrated into customers’ 3D sensing cameras, primarily used in mobile devices. In the industrial manufacturing market, our lasers are embedded in machine tools used for precision material processing across diverse industries, including semiconductor and microelectronics fabrication, electric vehicle and battery production, metal cutting and welding, and advanced manufacturing. Adoption of our Industrial Tech products is driven by the need to advance semiconductor and microelectronics technology roadmaps and by Industry 4.0 and 5.0 trends that emphasize greater manufacturing precision, flexibility, and sustainability. We have a global footprint that enables us to address global market opportunities for our products with employees engaged in research and development (“R&D”), administration, manufacturing, support and sales and marketing activities in various locations worldwide. We have manufacturing capabilities and facilities in North America, Asia-Pacific and Europe. Our headquarters are located in San Jose, California, and we employed approximat ely 10,562 full -time employees around the world as of June 28, 2025. 2 Table of Contents Lumentum was incorporated in Delaware as a wholly owned subsidiary of JDS Uniphase Corporation (“JDSU”) on February 10, 2015. In August 2015, the Company was spun-off from JDSU and became an independent publicly traded company through the distribution of our common stock by JDSU to its stockholders. In 2015, the remaining parent company, JDSU, was renamed Viavi Solutions Inc. (“Viavi”). Our business traces its origins to Uniphase Corporation, which was formed in 1979 and became publicly traded in 1992. Uniphase was originally a supplier of commercial lasers, and later became a leading supplier of optical transmission products. In 1999, JDS Fitel Inc., a pioneer in products for fiber optic networking which was formed in 1981, merged with Uniphase to become JDSU, a global leader in optical networking. Subsequent acquisitions by JDSU broadened the depth and breadth of what is now Lumentum’s businesses, as well as the intellectual property, technology and product offerings of the company. The fundamental laser and photonic component technologies which we acquired through various acquisitions form the basis of cloud and communications optical network infrastructure today. These technologies will continue to enable us to develop highly integrated products to satisfy our customers’ ever-increasing needs for smaller, lower power and lower cost optical and photonic products. In December 2018, we completed the acquisition of Oclaro, Inc. (“Oclaro”), which enhanced our product portfolio by adding Oclaro’s indium phosphide laser and photonic integrated circuit technologies, as well as its coherent component and module capabilities. These additions broadened our revenue mix and strengthened our position to meet the evolving needs of our customers. In August 2022, we completed the acquisition of NeoPhotonics Corporation (“NeoPhotonics”), which expanded our opportunities in optical components used in cloud and telecom network infrastructure. In August 2022, we completed a transaction to acquire", "item1a": "ITEM 1A. RISK FACTORS Investing in our common stock involves a high degree of risk. You should carefully consider the risks and uncertainties described below, together with all of the other information in this Annual Report on Form 10-K, including the section titled “Management’s Discussion and Analysis of Financial Condition and Results of Operations” and our consolidated financial statements and related notes, before making a decision to invest in our common stock. Our business, financial condition, results of operations or prospects could also be harmed by risks and uncertainties not currently known to us or that we currently do not believe are material. If any of the risks actually occur, our business, financial condition, results of operations and prospects could be adversely affected. In that event, the market price of our common stock could decline, and you could lose part or all of your investment. Risk Factor Summary Our business operations are subject to numerous risks, factors and uncertainties, including those outside of our control, which could cause our actual results to be harmed, including risks regarding the following: Risks Related to our Business • unfavorable economic and market conditions, including the impact of trade restrictions or regulations, including tariffs, duties and export controls; • our reliance on a limited number of suppliers and customers; • order cancellations, reductions or delays in delivery schedules by our customers or distributors; • failure of banking institutions and liquidity concerns at other financial institutions; • our backlog may not be an accurate indicator of our level and timing of future revenue; • our gross margins and operating margins may vary overtime; • challenges relating to supply chain constraints; • changes in technology and intense competition; • our ability to sell to a significant customer, as well as higher tariffs and other trade restrictions between the U.S. and other countries, including China and Thailand; • headwinds caused by heightened, scheduled, or threatened tariffs imposed by the U.S. or other countries; • the impact of a widespread health crisis; • our international operations structure; • volatility and maintenance of our real property portfolio; • our ability to timely procure components needed to manufacture our products; • our ability to manufacture our products; • our leverage in negotiations with large customers; • design and manufacturing defects or quality issues in our products; • changes in laws and the adoption and interpretation of administrative rules and regulations, including U.S. and international customs and export regulations; • our strategic transactions and implementation strategy for our acquisitions, including the Cloud Light acquisition; • restructuring and related charges; • changes in spending levels, demand and customer requirements for our products; • changes in tax laws; • fluctuations in foreign currency; 11 • our future capital requirements; • actual or perceived security or privacy breaches or incidents, as well as defects, errors or vulnerabilities in our technology and that of third-party providers; • the failure or absence of business continuity plans with respect to our global facilities and operations; • the unpredictability of our results of operations; • our ability to protect our product and proprietary rights; • factors relating to our intellectual property rights as well as the intellectual property rights of others; • actions taken by authorized or unauthorized resellers or distributors that adversely affect our reputation or violate import or export regulations; • litigation risks, including intellectual property litigation; • our reliance on licensed third-party technology; and • our ability to maintain an effective system of disclosure controls and internal control over financial reporting Risks Related to Human Capital • our ability to hire and retain key personnel • the effects of immigration policy on our ability to hire and retain employees; and • employment related disputes and claims Risks Related to Legal, Regulatory and Compliance • our ability to obtain government authorization to export our products; and • changes in social and environmental responsibility regulations, policies and provisions, as well as government, customer, business partner, investor or other stakeholder demands Risks Related to Our Common Stock • the volatility of the trading price of our common stock; • our ability to service our current and future debt; • dilution related to our convertible notes; • our intention not to pay dividends for the foreseeable future; • provisions of Delaware law and our certificate of incorporation and bylaws that may make a merger, tender offer or proxy contest difficult; and • exclusive forum provisions in our bylaws 12 Risks Related to Our Business Our operating results may be adversely affected by unfavorable changes in macroeconomics and market conditions and the uncerta", "item7": "ITEM 7. MANAGEMENT’S DISCUSSION AND ANALYSIS OF FINANCIAL CONDITION AND RESULTS OF OPERATIONS You should read the following discussion in conjunction with the audited consolidated financial statements and the corresponding notes included elsewhere in this Annual Report. This Management’s Discussion and Analysis of Financial Condition and Results of Operations contains forward-looking statements. The matters discussed in these forward-looking statements are subject to risk, uncertainties and other factors that could cause actual results to differ materially from those made, projected or implied in the forward-looking statements. Refer to “Risk Factors” and “Forward-Looking Statements” for a discussion of the uncertainties, risks and assumptions associated with these statements. Overview We are a leading provider of optical and photonic products and are recognized as an industry leader based on revenue and market share. Our products are essential to a range of cloud, artificial intelligence and machine learning (“AI/ML”), telecommunications, consumer, and industrial end-market applications. We believe the global markets in which Lumentum participates have fundamentally robust, long-term trends that will increase the need for our photonics products and technologies. We believe the world is becoming more reliant on ever-increasing amounts of data flowing through optical networks and data centers. Lumentum’s products and technology enable the scaling of these optical networks and data centers to higher capacities. AI/ML has caused a dramatic surge in the growing demands on data networking in cloud data centers and accelerated the usage of optical components and modules. We expect that the accelerating shift to digital and virtual approaches to many aspects of work and life will continue into the future. Virtual meetings, video calls, and hybrid in-person and virtual environments for work and other aspects of life will continue to drive strong needs for bandwidth growth and present dynamic new challenges that our technologies address. As manufacturers demand higher levels of precision, new materials, and factory and energy efficiency, suppliers of manufacturing tools globally are turning to laser-based approaches, including the types of lasers Lumentum supplies. Laser-based 3D sensing and LiDAR for security, industrial and automotive applications are rapidly developing markets. The technology enables computer vision applications that enhance security, safety, and new functionality in the electronic devices that people rely on every day. The use of LiDAR and in-cabin 3D sensing in automobile and delivery vehicles over time significantly adds to our long-term market opportunity. Additionally, we expect 3D-enabled machine vision solutions to expand significantly in industrial applications in the coming years. To maintain and grow our market and technology leadership positions, we are continually investing in new and differentiated products and technologies and customer programs that address both nearer-term and longer-term growth opportunities, both organically and through acquisitions, as well as continually improving and optimizing our operations. Over many years, we have developed close relationships with market-leading customers. We seek to use our core optical and photonic technologies and our volume manufacturing capability to expand into attractive emerging markets that benefit from advantages that optical or photonics-based solutions provide. We have two reportable segments, Cloud & Networking and Industrial Tech. The two operating segments were primarily determined based on how our Chief Operating Decision Maker (“CODM”) views and evaluates our operations. The CODM regularly reviews operating results to make decisions about resources to be allocated to the segments and to assess their performance. Our CODM allocates resources to the segments based on their business prospects, competitive factors, segment net revenue and segment profit. Segment profit includes operating expenses directly managed by operating segments, including research and development, and direct sales and marketing expenses. Segment profit does not include stock-based compensation, acquisition or integration related costs, amortization and impairment of acquisition-related intangible assets, restructuring and related charges, and certain other charges. Additionally, we do not allocate certain marketing and general and administrative expenses, as these expenses are not directly attributable to our operating segments. Cloud & Networking Our Cloud & Networking products comprise a comprehensive portfolio of optical and photonic chips, components, modules, and subsystems supplied to cloud data center operators, AI/ML infrastructure providers, and network equipment manufacturer customers who are building cloud data center and network infrastructures. Our products enable high-capacity optical links for cloud computing, AI/ML workloads, and data c"}','deep_research','2025-08-19','2026-06-14T00:04:29');
INSERT INTO company_profiles VALUES('MU','Micron Technology是全球第三大DRAM厂商，HBM(高带宽内存)市场#2(21%份额，超越三星)。AI GPU(H100/B200/GB300)必须搭配HBM，每代GPU的HBM含量翻倍增长。FY2026收入约$700亿(+193% YoY)，DRAM占79%。美国唯一HBM生产商。','["HBM3E — 量产中，AI GPU配套主力", "HBM4 — 2026 Q2量产，Vera Rubin分配", "DDR5 — 数据中心/PC内存", "LPDDR5X — 移动设备", "NAND闪存 — SSD/存储(占收入~21%，利润率较低)"]','三家寡头垄断(SK海力士58%/美光21%/三星21%)。三星因HBM良率问题掉到第三。美光是唯一美国HBM来源，具有国家安全战略价值。新建DRAM厂需$150-250亿+4-5年，进入壁垒极高。','1. 40年+DRAM制造IP不可复制 2. HBM TSV堆叠+先进封装深度合作 3. 美国唯一HBM来源——CHIPS Act资金支持 4. 与NVIDIA密切协作HBM4 36GB 12-hi定制设计 5. 2026年全部HBM产能售罄','["NVIDIA(HBM最大客户)", "AMD/Intel(GPU/CPU配套)", "超大规模云厂商(服务器DDR5)", "苹果/三星(移动LPDDR)"]','["自有晶圆厂(美国/日本/新加坡/中国台湾)", "设备来源: ASML/应用材料/LAM等", "先进封装合作: TSMC CoWoS"]','1. 三星HBM良率恢复将加剧竞争 2. DRAM周期性——历史上boom-bust明显 3. 中国限制(美光已被部分中国基建项目禁用) 4. NAND业务利润率低，拖累整体 5. 股价12个月涨8倍+，估值和情绪已极度乐观','HBM市场2025年~$250亿，预计2027年翻倍。每代GPU HBM含量: H100=80GB→B300=288GB→Rubin Ultra=512GB。','{"item1": "Item 1. Business, Overview. Industry Conditions AI-driven demand is accelerating and is outpacing industry supply. In 2025, we benefited from substantial improvements in DRAM pricing, volumes and margins as compared to 2024, reflecting strong demand growth, driven in part by the continued advancement of AI. During 2025, we shifted a portion of our DRAM supply to the data center and hyperscale cloud markets to meet the strong demand fueled by AI, with emphasis on HBM products, resulting in a revenue mix weighted more prominently toward segments experiencing higher growth. The pivot to higher-growth segments, together with our strong execution, robust overall industry DRAM demand, and constrained supply, has led to improved profitability across our DRAM portfolio. In 2025, NAND revenue increased from 2024 on higher bit shipments due to demand growth. The 2025 NAND gross margin percentage increased from 2024 due to cost reductions. We continue to prudently manage our NAND business to ensure we align our supply growth and technology node cadence with our projections of the demand environment. Throughout 2024, we experienced substantial improvements in pricing and margins due to improving market conditions as compared to 2023. Increasing demand growth, driven in part by deployment of AI and mostly normal customer inventories, combined with industry-wide supply discipline, resulted in an industry supply and demand balance that substantially improved from downturn conditions in memory and storage markets during 2023. In connection with improved market conditions in 2024, we reinstated our bonuses and phased out certain other temporary cost-saving measures that were implemented in 2023. In 2023, China’s Cyberspace Administration (the “CAC”) conducted a cybersecurity review of our products sold in China and decided that our products presented a cybersecurity risk. The CAC determined that critical information infrastructure operators in China may not purchase Micron products. The CAC decision has impacted our business, particularly in the domestic data center and networking markets in China, and we have been working to mitigate that impact. 51 | 2025 10-K Table of Contents Results of Operations Consolidated Results For the year ended 2025 2024 2023 Revenue $ 37,378 100 % $ 25,111 100 % $ 15,540 100 % Cost of goods sold 22,505 60 % 19,498 78 % 16,956 109 % Gross margin 14,873 40 % 5,613 22 % (1,416) (9) % Research and development 3,798 10 % 3,430 14 % 3,114 20 % Selling, general, and administrative 1,205 3 % 1,129 4 % 920 6 % Restructure and asset impairments 39 — % 1 — % 171 1 % Other operating (income) expense, net 61 — % (251) (1) % 124 1 % Operating income (loss) 9,770 26 % 1,304 5 % (5,745) (37) % Interest income (expense), net 19 — % (33) — % 80 1 % Other non-operating income (expense), net (135) — % (31) — % 7 — % Income tax (provision) benefit (1,124) (3) % (451) (2) % (177) (1) % Equity in net income (loss) of equity method investees 9 — % (11) — % 2 — % Net income (loss) $ 8,539 23 % $ 778 3 % $ (5,833) (38) % Total Revenue: Total revenue was impacted by the factors described in the section titled “Industry Conditions” above. These conditions drove substantial improvements in average selling prices throughout 2025 and 2024. Total revenue for 2025 increased 49% as compared to 2024 primarily due to increases in sales of both DRAM and NAND products. • Sales of DRAM products increased 62% primarily due to a low-40% range increase in average selling prices and a mid-teen percentage increase in bit shipments. • Sales of NAND products increased 18% primarily due to a high-teen percentage increase in bit shipments. Total revenue for 2024 increased 62% as compared to 2023 primarily due to increases in sales of both DRAM and NAND products. • Sales of DRAM products increased 60% primarily due to a mid-40% range increase in bit shipments and a low-teen percentage range increase in average selling prices. • Sales of NAND products increased 72% primarily due to a low-30% range increase in bit shipments and a low-30% percentage range increase in average selling prices. Consolidated Gross Margin: Our consolidated gross margin has been impacted by the factors described in the section titled “Industry Conditions” above and the effects of 2023 inventory write-downs on our 2024 and 2023 gross margin, as detailed in the table below. Our consolidated gross margin percentage improved to 40% for 2025 from 22% for 2024 as a result of improvements in margins for both DRAM and NAND products. DRAM margins improved primarily due to increases in average selling prices, an increased mix of higher-margin products, including HBM, and manufacturing cost reductions driven by improvements in product and process technology. NAND margins improved primarily due to manufacturing cost reductions. Our consolidated gross margin for 2024 reflected $987 million of benefit due to lower costs from the sale of inventories written down to their net realiza", "item1a": "Item 1A. Risk Factors, “Risks Related to Capitalization and Financial Markets—Changes in foreign currency exchange rates could materially adversely affect our business, results of operations, or financial condition.” The functional currency for all of our operations is the U.S. dollar. The substantial majority of our sales are transacted in the U.S. dollar; however, significant amounts of our operating expenses and capital expenditures, and certain assets and liabilities, are incurred in or exposed to other currencies, primarily the Canadian dollar, Chinese yuan, euro, Indian rupee, Japanese yen, Malaysian ringgit, New Taiwan dollar, and Singapore dollar. We have established currency risk management programs for our monetary assets and liabilities, investments in debt instruments, and forecasted future cash flows denominated in foreign currencies to hedge against fluctuations in the fair value and volatility of future cash flows caused by changes in currency exchange rates. We generally utilize currency forward contracts in these hedging programs, which reduce, but do not always entirely eliminate, the impact of currency exchange rate movements. We do not use derivative financial instruments for trading or speculative purposes. 61 | 2025 10-K Table of Contents Based on monetary assets and liabilities and investments in debt instruments denominated in foreign currencies, we estimate that a hypothetical 10% adverse change in exchange rates versus the U.S. dollar would result in losses of approximately $572 million as of August 28, 2025, and $480 million as of August 29, 2024. We hedge our exposure to changes in currency exchange rates by utilizing a rolling hedge strategy for our primary currency exposures with currency forward contracts that generally mature within three months. The effectiveness of our hedges is dependent, among other factors, upon our ability to accurately measure exposures on a timely basis. We may also hedge currency risk arising from foreign currency-denominated investments in debt instruments with currency forward contracts that generally mature within one year. To hedge the exposure of changes in cash flows from changes in currency exchange rates for certain capital expenditures and manufacturing costs, we may utilize currency forward contracts that generally mature within two years. See Item 8. Financial Statements and Supplementary Data, Notes to Consolidated Financial Statements, Note 17. Derivative Instruments. 62 Table of Contents ITEM 8. FINANCIAL STATEMENTS AND SUPPLEMENTARY DATA Index to Consolidated Financial Statements Consolidated Statements of Operations 64 Consolidated Statements of Comprehensive Income (Loss) 65 Consolidated Balance Sheets 66 Consolidated Statements of Changes in Equity 67 Consolidated Statements of Cash Flows 68 Notes to Consolidated Financial Statements 69 Report of Independent Registered Public Accounting Firm (PCAOB ID 238 ) 99 63 | 2025 10-K Table of Contents Micron Technology, Inc. Consolidated Statements of Operations (In millions, except per share amounts) For the year ended August 28, 2025 August 29, 2024 August 31, 2023 Revenue $ 37,378 $ 25,111 $ 15,540 Cost of goods sold 22,505 19,498 16,956 Gross margin 14,873 5,613 ( 1,416 ) Research and development 3,798 3,430 3,114 Selling, general, and administrative 1,205 1,129 920 Restructure and asset impairments 39 1 171 Other operating (income) expense, net 61 ( 251 ) 124 Operating income (loss) 9,770 1,304 ( 5,745 ) Interest income 496 529 468 Interest expense ( 477 ) ( 562 ) ( 388 ) Other non-operating income (expense), net ( 135 ) ( 31 ) 7 9,654 1,240 ( 5,658 ) Income tax (provision) benefit ( 1,124 ) ( 451 ) ( 177 ) Equity in net income (loss) of equity method investees 9 ( 11 ) 2 Net income (loss) $ 8,539 $ 778 $ ( 5,833 ) Earnings (loss) per share Basic $ 7.65 $ 0.70 $ ( 5.34 ) Diluted 7.59 0.70 ( 5.34 ) Number of shares used in per share calculations Basic 1,116 1,105 1,093 Diluted 1,125 1,118 1,093 See accompanying notes to consolidated financial statements. 64 Table of Contents Micron Technology, Inc. Consolidated Statements of Comprehensive Income (Loss) (In millions) For the year ended August 28, 2025 August 29, 2024 August 31, 2023 Net income (loss) $ 8,539 $ 778 $ ( 5,833 ) Other comprehensive income (loss), net of tax Gains (losses) on derivative instruments 92 142 234 Pension liability adjustments 6 3 11 Unrealized gains (losses) on investments 4 33 6 Foreign currency translation adjustments — — ( 3 ) Other comprehensive income (loss) 102 178 248 Total comprehensive income (loss) $ 8,641 $ 956 $ ( 5,585 ) See accompanying notes to consolidated financial statements. 65 | 2025 10-K Table of Contents Micron Technology, Inc. Consolidated Balance Sheets (In millions, except par value amounts) As of August 28, 2025 August 29, 2024 Assets Cash and cash equivalents $ 9,642 $ 7,041 Short-term investments 665 1,065 Receivables 9,265 6,615 Inventories 8,355 8,875 Other current assets 914 776 Tot", "item7": "ITEM 7. MANAGEMENT’S DISCUSSION AND ANALYSIS OF FINANCIAL CONDITION AND RESULTS OF OPERATIONS This discussion should be read in conjunction with the consolidated financial statements and accompanying notes for the year ended August 28, 2025. All period references are to our fiscal periods unless otherwise indicated. Our fiscal year is the 52 - or 53-week period ending on the Thursday closest to August 31. Fiscal 2025, 2024, and 2023 each contained 52 weeks. All tabular dollar amounts are in millions, except per share amounts. Overview For an overview of our business, see Part I, Item 1. Business, Overview. Industry Conditions AI-driven demand is accelerating and is outpacing industry supply. In 2025, we benefited from substantial improvements in DRAM pricing, volumes and margins as compared to 2024, reflecting strong demand growth, driven in part by the continued advancement of AI. During 2025, we shifted a portion of our DRAM supply to the data center and hyperscale cloud markets to meet the strong demand fueled by AI, with emphasis on HBM products, resulting in a revenue mix weighted more prominently toward segments experiencing higher growth. The pivot to higher-growth segments, together with our strong execution, robust overall industry DRAM demand, and constrained supply, has led to improved profitability across our DRAM portfolio. In 2025, NAND revenue increased from 2024 on higher bit shipments due to demand growth. The 2025 NAND gross margin percentage increased from 2024 due to cost reductions. We continue to prudently manage our NAND business to ensure we align our supply growth and technology node cadence with our projections of the demand environment. Throughout 2024, we experienced substantial improvements in pricing and margins due to improving market conditions as compared to 2023. Increasing demand growth, driven in part by deployment of AI and mostly normal customer inventories, combined with industry-wide supply discipline, resulted in an industry supply and demand balance that substantially improved from downturn conditions in memory and storage markets during 2023. In connection with improved market conditions in 2024, we reinstated our bonuses and phased out certain other temporary cost-saving measures that were implemented in 2023. In 2023, China’s Cyberspace Administration (the “CAC”) conducted a cybersecurity review of our products sold in China and decided that our products presented a cybersecurity risk. The CAC determined that critical information infrastructure operators in China may not purchase Micron products. The CAC decision has impacted our business, particularly in the domestic data center and networking markets in China, and we have been working to mitigate that impact. 51 | 2025 10-K Table of Contents Results of Operations Consolidated Results For the year ended 2025 2024 2023 Revenue $ 37,378 100 % $ 25,111 100 % $ 15,540 100 % Cost of goods sold 22,505 60 % 19,498 78 % 16,956 109 % Gross margin 14,873 40 % 5,613 22 % (1,416) (9) % Research and development 3,798 10 % 3,430 14 % 3,114 20 % Selling, general, and administrative 1,205 3 % 1,129 4 % 920 6 % Restructure and asset impairments 39 — % 1 — % 171 1 % Other operating (income) expense, net 61 — % (251) (1) % 124 1 % Operating income (loss) 9,770 26 % 1,304 5 % (5,745) (37) % Interest income (expense), net 19 — % (33) — % 80 1 % Other non-operating income (expense), net (135) — % (31) — % 7 — % Income tax (provision) benefit (1,124) (3) % (451) (2) % (177) (1) % Equity in net income (loss) of equity method investees 9 — % (11) — % 2 — % Net income (loss) $ 8,539 23 % $ 778 3 % $ (5,833) (38) % Total Revenue: Total revenue was impacted by the factors described in the section titled “Industry Conditions” above. These conditions drove substantial improvements in average selling prices throughout 2025 and 2024. Total revenue for 2025 increased 49% as compared to 2024 primarily due to increases in sales of both DRAM and NAND products. • Sales of DRAM products increased 62% primarily due to a low-40% range increase in average selling prices and a mid-teen percentage increase in bit shipments. • Sales of NAND products increased 18% primarily due to a high-teen percentage increase in bit shipments. Total revenue for 2024 increased 62% as compared to 2023 primarily due to increases in sales of both DRAM and NAND products. • Sales of DRAM products increased 60% primarily due to a mid-40% range increase in bit shipments and a low-teen percentage range increase in average selling prices. • Sales of NAND products increased 72% primarily due to a low-30% range increase in bit shipments and a low-30% percentage range increase in average selling prices. Consolidated Gross Margin: Our consolidated gross margin has been impacted by the factors described in the section titled “Industry Conditions” above and the effects of 2023 inventory write-downs on our 2024 and 2023 gross margin, as detailed in the table below. Our consolidated gros"}','deep_research','2025-10-03','2026-06-14T00:04:29');
INSERT INTO company_profiles VALUES('PLAB','Photronics是全球两家merchant光掩模公司之一(另一家Toppan)。光掩模是芯片光刻的''母版模具''——每颗芯片的每层电路都需要独立掩模(每个设计20-80+张)。FY2025收入$8.49亿。市值~$19亿。EUV掩模无法制造是核心短板。','["主流IC光掩模(DUV/i-line, 28nm+)", "高端IC光掩模(sub-14nm多重曝光DUV)", "FPD光掩模(TFT-LCD/AMOLED)", "注: 不具备EUV光掩模制造能力"]','Merchant掩模双寡头: PLAB~21%+Toppan~20%=~41%，captive(TSMC/Intel/Samsung)~55-60%。PLAB在亚洲通过台湾和厦门JV积极扩张份额。但EUV掩模(最高ASP、增长最快)完全被captive垄断——这是PLAB的结构性天花板。','1. 电子束掩模刻写机($5000万-1亿/台)——高资本壁垒 2. Class 1超净室+纳米级工艺(数十年积累) 3. 客户认证周期长(晶圆厂不轻易换掩模供应商) 4. 厦门JV服务中国成熟制程扩张','["2家>10%收入(大概率台积电和三星)", "亚洲收入占比>70%", "晶圆厂/IDM/Fabless设计公司"]','["掩模刻写机: JEOL/NuFlare(日本)", "石英基板", "光学级材料"]','1. EUV掩模captive化——最高价值段PLAB永远无法进入 2. Captive产能持续扩张压缩merchant可寻址市场 3. Q2 FY26营收miss+证券欺诈调查(税务披露问题) 4. 客户集中(2家>10%) 5. 半导体周期性——设计开工减少=掩模需求下降','全球光掩模市场(captive+merchant)约$41亿。PLAB~$8.5亿(21%)。成熟制程中国扩张+AI设计增多是增量驱动。','{"item1": "ITEM 1. BUSINESS Specific industry and technical terms used in this section are defined in the subsection entitled “Glossary of Terms and Acronyms,” found below the Table of Contents. Business Overview Photronics, Inc. (and its subsidiaries, collectively referred to herein as “Photronics”, the “Company”, “we”, “our”, or “us”) is one of the world’s leading manufacturers of photomasks, which are high precision photographic quartz or glass plates containing microscopic images of electronic circuits. Photomasks are a key element in the manufacture of ICs and FPDs and are used as masters to transfer circuit patterns onto semiconductor wafers and FPD substrates during the fabrication of ICs, a variety of FPDs and, to a lesser extent, other types of electrical and optical components. We have eleven manufacturing facilities, which are located in Taiwan (3), China (2), South Korea (1), the United States (3), and Europe (2). Our principal executive offices are located at 15 Secor Road, Brookfield, Connecticut, 06804, telephone (203) 775-9000. Our website address is http://www.photronics.com. We make available, free of charge through our website, our Forms 10-K, Definitive Proxy Statements on Schedule 14A, Forms 10-Q, Current Reports on Form 8-K, and any amendments to these reports as soon as reasonably practicable after such materials are electronically filed with or furnished to the SEC. The information found on, or incorporated into, our website is not part of this or any other report we file with or furnish to the SEC. The SEC also maintains a website at http://www.sec.gov that contains reports, proxy statements and other information regarding SEC registrants, including Photronics. Segment We operate as a single reporting segment as a manufacturer of photomasks, which are high precision quartz or glass plates containing microscopic images of electronic circuits for use in the fabrication of IC’s and FPDs. In accordance with the ASC 280 – “Segment Reporting” Topic of the ASC, the Company’s chief operating decision maker has been identified as the Chief Executive Officer, who reviews operating results to make decisions about allocating resources and assessing performance for the entire Company. Existing guidance, which is based on a management approach to segment reporting, establishes requirements to report selected segment information quarterly and to report annually entity-wide disclosures about products and services, major customers, and the countries in which the entity holds material assets and reports revenue. All material operating units qualify for aggregation under “Segment Reporting” due to their similar customer base and similarities in: economic characteristics; nature of products and services; and procurement, manufacturing and distribution processes. Since the Company operates in one segment, all financial information required by “Segment Reporting” can be found in the accompanying consolidated financial statements. Industry We manufacture photomasks, which are used as masters to transfer circuit patterns onto semiconductor wafers and FPD substrates. The photomasks we manufacture incorporate circuit designs provided to us on a confidential basis by our customers. Photomasks are typically sold in sets comprised of layers, with each layer having a distinct pattern that is etched onto a different photomask. The resulting series of photomasks is then used to image the circuit patterns onto each successive layer of a semiconductor wafer or FPD substrate. The typical manufacturing process for a photomask involves the receipt and conversion of circuit design data to manufacturing pattern data. A lithography system then exposes the circuit pattern onto a photomask blank. The exposed areas are developed and etched to imprint the pattern on the photomask. The photomask is then inspected for defects and conformity to the customer’s design data. After the repair of any defects, the photomask is cleaned, any required pellicles (protective translucent membranes) are applied and, after final inspection, the photomask is shipped to the customer. “High-end” photomasks support 28 nanometer and smaller design nodes for ICs and Generation 10.5+, AMOLED, and LTPS display-based process technologies for FPDs. However, 32 nanometer and above geometries for semiconductors and Generation 8 and below (excluding AMOLED and LTPS) process technologies for displays, which we refer to as “mainstream” photomasks, constitute the majority of designs currently being fabricated in volume. At these geometries and at various high-end nodes, we can produce full lines of photomasks. Moreover, there is no significant technology employed by our competitors that is not available to us. We expect advanced-generation designs to continue to be developed, and we believe we are well positioned to service an increasing volume of this business as a result of our ongoing investments in manufacturing processes and technology in the regions where our cus", "item1a": "Item 1A. Risk Factors” for more information. 20 Table of Contents Governance Management is responsible for the day-to-day management of the risks we face, while our Board of Directors has ultimate responsibility for the oversight of risk management, including risks from cybersecurity threats. The Board of Directors has delegated primary oversight of cybersecurity risk to the Cyber Security Risk Management Committee. The Committee, in turn, ensures its members either possess or have access to relevant cybersecurity and risk management expertise to effectively challenge and guide management''s program. The Committee regularly assesses how management is managing these risks and reports on its activities to the full Board of Directors at least quarterly to promote effective coordination and ensure the entire Board remains apprised of the cybersecurity risk landscape and the program''s effectiveness. The day-to-day cybersecurity program is led by the Company’s Vice President, IT Infrastructure & Information Security. This role is supported by a dedicated security team and reports directly to the Chief Executive Officer. The Vice President, IT Infrastructure & Information Security provides formal, quarterly updates to the Cyber Security Risk Management Committee. These updates cover cyber risk management governance, the status of ongoing efforts to strengthen cybersecurity effectiveness, key risk metrics and the material outcomes of risk assessments, and significant cybersecurity-related news events impacting the industry. In addition to scheduled reports, the Board of Directors engages in ad hoc conversations with management to discuss any significant updates to our cybersecurity risk management and initiatives, particularly in response to emerging threats. ITEM 2. PROPERTIES The following table presents certain information about the Company’s photomask manufacturing facilities: Location Type of Interest Allen, Texas Owned Boise, Idaho Owned Brookfield, Connecticut Owned Bridgend, Wales Leased Cheonan, South Korea Owned Hefei, China Owned (1) Dresden, Germany Leased Hsinchu, Taiwan Owned (1) Hsinchu, Taiwan Leased Taichung, Taiwan Owned (1) Xiamen, China Owned (1) (1) We own our manufacturing facilities in Hefei, Taichung, Xiamen, and one of our manufacturing facilities in Hsinchu. However, we lease the related land at these sites. We believe our facilities, with planned expansions, are adequate to support our current and near-term requirements. ITEM 3. LEGAL PROCEEDINGS Please refer to Note 16 – Commitments and Contingencies to our consolidated financial statements in Part II, Item 8 of this report for information on legal proceedings involving the Company. ITEM 4. MINE SAFETY DISCLOSURES Not applicable. 21 Table of Contents PART II ITEM 5. MARKET FOR REGISTRANT’S COMMON EQUITY, RELATED STOCKHOLDER MATTERS AND ISSUER PURCHASES OF EQUITY SECURITIES Market Information Our common stock is traded on the NASDAQ Global Select Market (“NASDAQ”) under the symbol PLAB. Approximate Number of Holders of Common Stock Based on available information, as of December 11, 2025, we have 212 registered shareholders. Dividends To date, we have not paid any cash dividends on Photronics shares, and, for the foreseeable future, we anticipate that earnings will continue to be retained for use in our business. Securities Authorized for Issuance Under Equity Compensation Plans The information regarding our equity compensation required to be disclosed by Item 201(d) of Regulation S-K is incorporated by reference from the Photronics, Inc. 2026 Definitive Proxy Statement in Item 12 of Part III of this report. The 2026 Definitive Proxy Statement will be filed within 120 days after our fiscal year ended October 31, 2025. Stock Price Performance Graph 22 Table of Contents Purchase of Equity Securities by Registrant and Affiliated Purchasers In September 2020, the Company’s Board of Directors authorized the repurchase of up to $100 million of its common stock, pursuant to a repurchase plan under Rule 10b-18 of the Exchange Act. The repurchase authorization by the Board of Directors has no expiration date, does not obligate the Company to acquire any common stock, and is subject to market conditions. From September 2020 through October 2022, the Company repurchased 5.8 million shares at a cost of $68.3 million. In August 2024, the Board of Directors authorized an increase to the Company’s existing share repurchase program from the remaining $31.7 million up to $100 million. In June 2025, the Board of Directors authorized an additional $25 million share repurchase. No shares were repurchased during the three-month period ended October 31, 2025. In fiscal year 2025, the Company repurchased 5.0 million shares at a cost of $97.4 million (an average of $19.52 per share). All shares repurchased under the program have been retired prior to the end of the fiscal year in which they were purchased. As of October 31, 2025, $27.6 million remained available u", "item7": "Item 7. Management’s Discussion and Analysis of Financial Condition and Results of Operations of Photronics Inc.’s Annual Report on Form 10-K for the fiscal year ended October 31, 2024, filed with the SEC on December 19, 2024. Overview We sell substantially all of our photomasks to designers and manufacturers of IC and FPD electronic devices. Photomask technology is also being applied to the fabrication of other high-technology products including advanced packaging modules, micro optical components for applications such as virtual reality/augmented reality and silicon photonics, micro-electronic mechanical systems (MEMS), and diverse nanotechnology applications. Our selling cycle is tightly interwoven with the development and release of new semiconductor and display designs and applications, particularly as they relate to the semiconductor industry''s migration to more advanced design nodes and fabrication processes. The demand for photomasks is primarily correlated with new product design activity and to a lesser extent scaling up of manufacturing of end products. Consequently, an increase in semiconductor or display sales does not always result in a corresponding increase in photomask sales. To the extent integrated circuit and flat panel display applications rely less on new design activity, it could result in a reduction in demand for photomasks. In addition, new design methodologies driving a reduction in complexity of photomasks could also reduce demand for photomasks ‒ even if the demand for semiconductors and FPDs increases. More broadly, advances in semiconductor, display, and photomask design and production methods that shift the burden of achieving device performance away from lithography could also reduce the demand for photomasks. While there is no indication today that such diminishing of long range photomask demand is occurring or will occur, the microelectronics industry has been volatile, experiencing periodic downturns and slowdowns in design activity. These negative trends have been characterized by, among other things, diminished product demand, excess production capacity, and accelerated erosion of selling prices with a concomitant effect on revenue and profitability. We are typically required to fulfill customer orders within a short period of time, sometimes within twenty-four hours. This results in a minimal level of backlog orders, typically one to two weeks of backlog for IC photomasks and two to three weeks of backlog for FPD photomasks. However, the demand for some IC photomasks can extend longer than the traditional time period; thus, for some products, our backlog can expand to as long as two to three months. The global semiconductor and FPD industries are driven by end markets which have broad application in the global economy including but not limited to consumer-driven applications, data centers that support AI implementation, electric vehicles and national security. While we cannot predict the timing of the industry''s transition to volume production of next-generation technology nodes, or the timing of up and down-cycles with precise accuracy, we believe that such transitions and cycles will continue into the future, beneficially and adversely affecting our business, financial condition, and operating results as they occur. We believe our ability to remain successful in these environments is dependent upon the achievement of our goals of being a service and technology leader and efficient solutions supplier, which we believe should enable us to continually reinvest in our global infrastructure. We are focused on improving our competitiveness by advancing our technology and reducing costs and, in connection therewith, have invested and plan to continue to invest in manufacturing equipment to serve both the high-end photomask and mainstream markets. As we face challenges that require us to make significant improvements in our competitiveness, we continue to implement programs to streamline, drive efficiency and reduce cost in our infrastructure. State-of-the-art production for semiconductor masks is considered to be 7 nanometer and smaller including EUV lithography for ICs and Generation 8.6 AMOLED display-based process technologies for FPDs. However, we define our high-end product category as 28nm and below for semiconductors and Generation 10.5 plus, Generation 6 and 8 AMOLED and LTPS for displays. This is consistent with current merchant mask industry definitions. Moreover, design nodes above 28nm and FPD processes for standard LCD displays below Generation 10 are considered mainstream or standard products. At these geometries and various high-end nodes, we can produce full lines of photomasks, and there is no significant technology employed by our competitors that is not available to us. We expect advanced-generation designs to continue to move to production throughout fiscal 2026, and we believe we are well positioned to service an increasing volume of this business as a "}','deep_research','2025-12-17','2026-06-14T00:04:29');
INSERT INTO company_profiles VALUES('AXTI','AXT Inc是InP(磷化铟)衬底双寡头之一(~35%份额,另一家住友~40%)。InP衬底是EML激光芯片的物理基础——没有InP就没有800G/1.6T光模块。中国子公司(北京通美)受铟出口管制影响。FY2025收入$8830万(-11% YoY)。目前亏损(EPS -$0.49)。','["InP(磷化铟)衬底 — 光通信EML/光检测器基础", "GaAs(砷化镓)衬底 — LED/无线", "GaSb(锑化镓)衬底 — 国防/红外", "InP是主要增长驱动(创纪录>$1700万/季度)"]','双寡头: AXT~35%/住友~40%=~75%全球InP产能。其余: JX Advanced Metals/InPact(法)/小规模中国厂。Coherent/Lumentum不自制衬底。InP价格涨250%(中国管控后)。关键差异: 住友在日本(不受中国管制)，AXT在中国(受管制)——结构性劣势。','1. VGF(垂直梯度凝固)专有晶体生长——低位错密度/高均匀性 2. 20年+InP晶体生长经验 3. 多年客户认证周期(换衬底供应商周期长) 4. 但: InP不是不可复制的技术——住友用VB法同样优秀','["EML激光芯片厂: Lumentum/Coherent/三菱", "光检测器/光子IC厂商", "国防/红外应用(GaSb)"]','["铟(Indium)——中国控制65%+全球供应", "磷——相对充裕", "北京通美子公司是生产中心也是供应链风险"]','1. 中国铟出口管控直接限制AXT(北京通美)产能——Q4 2025收入被砍 2. CEO套现$1710万(公司市值才$64亿——比例大) 3. $64亿市值 vs $8800万收入+亏损=极端投机估值 4. 住友(日本)不受中国管制——竞争对手结构性更优 5. 小公司执行风险——65M股outstanding','InP晶圆市场$1.98亿(2025)→$3.85-6.28亿(2030-35,CAGR 12-20%)。1.6T每模块InP面积翻倍——结构性增长。','{"item1": "Item 1. Business AXT is a worldwide materials science company that develops and produces high-performance compound and single element semiconductor substrates, also known as wafers. Two of our consolidated subsidiaries produce and sell certain raw materials some of which are used in our substrate manufacturing process and some of which are sold to other companies. Our substrate wafers are used when a typical silicon substrate wafer cannot meet the performance requirements of a semiconductor or optoelectronic device. The dominant substrates used in producing semiconductor chips and other electronic circuits are made from silicon. However, certain chips may become too hot or perform their function too slowly if silicon is used as the base material. In addition, optoelectronic applications, such as LED lighting and chip-based lasers, do not use silicon substrates because they require a waveform frequency that cannot be achieved using silicon. Alternative or specialty materials are used to replace silicon as the preferred base in these situations. Our wafers provide such alternative or specialty materials. We do not design or manufacture the chips. We add value by researching, developing and producing the specialty material wafers. We have two product lines: specialty material substrates and raw materials integral to these substrates. Our compound substrates combine indium with phosphorous (indium phosphide: InP) or gallium with arsenic (gallium arsenide: GaAs). Our single element substrates are made from germanium (Ge). InP is a high-performance semiconductor wafer substrate used in broadband and fiber optic applications, 5G infrastructure and data center connectivity. Data centers use InP devices for high-speed optical data transmission. We believe the growth of AI applications is increasing the need for high-speed data transfer, which may enable a growing increase in InP substrate demand for such data centers. Currently, InP substrates are being used in certain consumer products, including proximity sensors and other sensors in mobile devices. Semi-insulating GaAs substrates are used to create various high-speed microwave components, including power amplifier chips used in cell phones, satellite communications and broadcast television applications. Semi-conducting GaAs substrates are used to create opto-electronic products, such as light emitting diodes (LEDs) that are used in a wide range of applications including automotive lighting, horticulture, signage, display, sensors and machine vision. Semi-conducting GaAs substrates are also used in making industrial lasers. GaAs wafers could also be used for making vertical cavity surface emitting lasers (VCSELs) for facial recognition. Ge substrates are used in applications such as solar cells for space and terrestrial photovoltaic applications. Our supply chain strategy includes several consolidated raw material companies. One of these consolidated companies produces pyrolytic boron nitride (pBN) crucibles used in the high temperature (typically in the range 500 C to 1,500 C) growth process of single crystal ingots, effusion rings when growing OLED (Organic Light Emitting Diode) tools, epitaxial layer growth in MOCVD (Metal-Organic Chemical Vapor Deposition) reactors and MBE (Molecular Beam Epitaxy) reactors. We use these pBN crucibles in our own ingot growth processes and they are also sold in the open market to other companies. A second consolidated company converts raw gallium to purified gallium. We use purified gallium in producing our GaAs substrates and it is also sold in the open market to other companies for use in producing magnetic materials, high temperature thermometers, single crystal ingots, including gallium arsenide, gallium nitride, gallium antimonite and gallium phosphide ingots, and other materials and alloys. In addition to purified gallium, the second consolidated company also produces InP base material which we then use to grow single crystal ingots. Our substrate product group generated 67%, 68%, and 63% of our consolidated revenue and our raw materials product group generated 33%, 32%, and 37% for 2025, 2024, and 2023, respectively. The following chart shows our substrate products and their materials, diameters and illustrative applications and shows our raw materials group primary products and their illustrative uses and applications. 3 Table of Contents Products Substrate Group and Wafer Diameter Sample of Applications Indium Phosphide • Data center connectivity using light/lasers (InP) • High-speed data transfer in data centers 2”, 3”, 4”, 6” • 5G communications • Fiber optic lasers and detectors • Consumer devices • Passive Optical Networks (PONs) • Silicon photonics • Photonic Integrated circuits (PICs) • Thermo-Photovoltaics (TPV’s) • RF amplifier and switching (military wireless & 5G) • Infrared light-emitting diode (LEDs) motion control • Lidar for robotics and autonomous vehicles • Infrared thermal imaging Gallium Arsenide • Wi-", "item1a": "Item 1A. Risk Factors – Risks Related to International Aspects of Our Business. Board of Director Changes On July 11, 2025, Ms. Christine Russell, our independent director, Chair of the Audit Committee, member of the Compensation Committee and the Nominating and Corporate Governance Committee, passed away. On July 14, 2025, we notified The Nasdaq Stock Market LLC (“Nasdaq”) that due to the passing of Ms. Russell, our Audit Committee had been reduced to two independent directors, and we were not compliant with Nasdaq Listing Rule 5605(c)(2)(A), which requires the Audit Committee to be comprised of a minimum of three independent directors, and our non-compliance was confirmed by Nasdaq on July 18, 2025. On July 29, 2025, we appointed Mr. Jesse Chen to serve as the Chair of the Audit Committee. Mr. Chen currently serves as an independent director, lead director, Chair of the Nominating and Governance Committee, and a member of the Audit Committee and Compensation Committee. In addition, on July 29, 2025, we appointed Leonard J. Leblanc to the Board of Directors (the “Board”) to fill the vacancy on the Board due to the passing of Ms. Russell. Mr. Leblanc is serving as a Class III director with a maximum term expiring on July 29, 2027, or until his successor is duly elected and qualified. In connection with Mr. Leblanc’s appointment to the Board, the Board considered the compensation Mr. Leblanc previously received during his term as director emeritus, and determined that Mr. Leblanc is not independent under the Nasdaq Listing Rules as his total compensation exceeded $120,000 during January 1, 2022 to December 31, 2022. From January 1, 2023 to December 31, 2023, Mr. Leblanc’s total compensation did not exceed $120,000 and Mr. Leblanc did not receive any further compensation from us after December 29, 2023. As such, after December 31, 2022, Mr. Leblanc would not have received any compensation from us in excess of $120,000 during any period of twelve consecutive months in the three year look-back period preceding January 1, 2026, and he would therefore be considered independent under the Nasdaq Listing Rules on January 1, 2026. Other than the compensation previously received as director emeritus, the Board has determined that Mr. Leblanc meets all independence requirements for a member of the audit committee under Rule 10A-3 of the Securities and Exchange Act of 1934, as amended, and the other independence requirements under the Nasdaq Listing Rules. 56 Table of Contents The Board also considered Mr. Leblanc’s previous service as a director and chair of the Audit Committee. Based on Mr. Leblanc’s experience and previous service with us, the Board determined that Mr. Leblanc''s familiarity with our operations, business, supply-chain and manufacturing strategies, and intricacies of our corporate structure was necessary to our current needs. The Board believed that the unforeseen passing of Ms. Russell during a critical period in our operations further necessitated the appointment of a director who is already familiar with our financial operations and our management under the current environment and economic conditions. Accordingly, the Board determined that the appointment of Mr. Leblanc to our Audit Committee as a non-independent director was in the best interests of the Company and our stockholders in reliance on the exception provided under applicable Nasdaq Listing Rules for membership on the Audit Committee, Compensation Committee and Nominating and Corporate Governance Committee under exceptional and limited circumstances. Based on the foregoing determination, the Board also appointed Mr. Leblanc to serve on the Audit Committee, Compensation Committee and Nominating and Corporate Governance Committee in reliance on the limited exception provided under the Nasdaq Listing Rules. Mr. LeBlanc’s independence under the Nasdaq Listing Rules will be re-evaluated by the Board on or after January 1, 2026. On January 26, 2026, the Board re-evaluated Mr. LeBlanc’s independence under the Nasdaq Listing Rules, and determined that Mr. LeBlanc is now independent under the Nasdaq Listing Rules. The Board has previously determined that Mr. LeBlanc meets all independence requirements for a member of the audit committee under Rule 10A-3 of the Securities and Exchange Act of 1934, as amended, and the other independence requirements under the Nasdaq Listing Rules. Upon the Board’s determination that Mr. LeBlanc is now independent under the Nasdaq Listing Rules, the Company’s Audit Committee will consist of three independent directors as required by Nasdaq Listing Rule 5605(c)(2)(A). On January 30, 2026, we received notification from the Nasdaq Listing Qualifications that we have regained compliance with Nasdaq Listing Rule 5605(c)(2). Effective upon Mr. LeBlanc’s determination as an independent director by the Board, Mr. Chen stepped down as Chair of the Audit Committee and the Board appointed Mr. LeBlanc as Chair of the Audit Commi", "item7": "Item 7. Management ’ s Discussion and Analysis of Financial Condition and Results of Operations In addition to historical information, the following discussion contains forward-looking statements that are subject to risks and uncertainties. Actual results may differ substantially from those referred to herein due to a number of factors, including but not limited to risks described in the section entitled Item 1A. “Risk Factors” and elsewhere in this Annual Report on Form 10-K. This discussion should be read in conjunction with our consolidated financial statements and related notes included elsewhere in this Form 10-K. Critical Accounting Policies and Estimates We prepare our consolidated financial statements in accordance with accounting principles generally accepted in the United States of America (“U.S. GAAP”). Accordingly, we make estimates, assumptions and judgments that affect the amounts reported on our consolidated financial statements. These estimates, assumptions and judgments about future events and their effects on our results cannot be determined with certainty, and are made based upon our historical experience and on other assumptions that are believed to be reasonable under the circumstances. These estimates may change as new events occur or additional information is obtained, and we may periodically be faced with uncertainties, the outcomes of which are not within our control and may not be known for a prolonged period of time. We have identified the policies below as critical to our business operations and understanding of our financial condition and results of operations. Critical accounting policies are material to the presentation of our consolidated financial statements and require us to make difficult, subjective or complex judgments that could have a material effect on our financial condition and results of operations. They may require us to make assumptions about matters that are highly uncertain at the time of the estimate. Different estimates that we could have used, or changes in the estimate that are reasonably likely to occur, may have a material impact on our financial condition or results of operations. We also refer you to Note 1 to our consolidated financial statements included elsewhere in this Annual Report on Form 10-K. 51 Table of Contents Revenue Recognition and Sales Returns We manufacture and sell high-performance compound semiconductor substrates including indium phosphide, gallium arsenide and germanium wafers, and our consolidated subsidiaries sell certain raw materials, including high purity gallium (6N and 7N Ga), pyrolytic boron nitride (pBN) crucibles and boron oxide (B2O3). After we ship our products, there are no remaining obligations or customer acceptance requirements that would preclude revenue recognition. Our products are typically sold pursuant to purchase orders placed by our customers, and our terms and conditions of sale do not require customer acceptance. We account for a contract with a customer when there is a legally enforceable contract, which could be the customer’s purchase order, the rights of the parties are identified, the contract has commercial terms, and collectibility of the contract consideration is probable. The majority of our contracts have a single performance obligation to transfer products and are short term in nature, usually less than six months. Our revenue is measured based on the consideration specified in the contract with each customer in exchange for transferring products that are generally based upon a negotiated, formula, list or fixed price. Revenue is recognized when control of the promised goods is transferred to our customer, which is either upon shipment from our dock, receipt at the customer’s dock, or removal from consignment inventory at the customer’s location, in an amount that reflects the consideration we expect to be entitled to receive in exchange for those goods. ​ We have elected to account for shipping and handling as activities to fulfill the promise to transfer the goods. As such, shipping and handling fees billed to customers in a sales transaction are recorded in revenue. Shipping and handling costs incurred are recorded in cost of revenue. Sales taxes and value added taxes in foreign jurisdictions that are collected from customers and remitted to governmental authorities are accounted for on a net basis and, therefore, are excluded from revenue. ​ We do not provide training, installation or commissioning services. We accrue for future returns based on historical data, prior experience, current economic trends and changes in customer demand at the time revenue is recognized. We do not recognize any asset associated with the incremental cost of obtaining revenue generating customer contracts. As such, sales commissions and other related expenses are expensed as incurred, given that the expected period of benefit is less than one year. ​ Accounts Receivable and Allowance for Credit Losses Accounts rec"}','deep_research','2026-03-17','2026-06-14T00:04:29');
INSERT INTO company_profiles VALUES('CRDO','Credo Technology是AI数据中心高速连接芯片龙头，专注SerDes(串行器/解串器)和DSP(数字信号处理)技术。核心产品AEC(有源电缆)在机架内5-7m短距互联占据~73%市场份额。FY2026收入$13.4亿(+206% YoY)，毛利率68.3%。','["HiWire AEC(有源电缆) — 主营，内嵌SerDes芯片的铜缆，解决短距高速信号衰减", "光PAM4 DSP(ZeroFlap) — 光模块内DSP芯片，推动LPO架构", "SerDes IP授权 — 卖IP给定制芯片设计方(Amazon Trainium等)", "SerDes Chiplet — 异构集成用独立芯片粒", "Line Card PHY/Retimer — 交换机信号调理芯片"]','AEC市场~73%份额的领导者。主要竞争者: Marvell(Golden Cable 2025年入场)、Broadcom(内部SerDes)、Alphawave(SerDes IP)。CRDO的优势是专注连接+n-1制程成本优势，劣势是产品线窄、无法捆绑销售。','n-1制程优势: 用成熟工艺节点实现224G SerDes前沿性能，模拟电路不依赖先进制程。微软HiWire Switch开源合作建立部署先发优势。2026年5月收购DustPhotonics(硅光子PIC)，构建SerDes→光DSP→硅光子垂直栈。','["微软Azure(最大客户，Q4 FY26占34%，从FY25的67%改善)", "4家超大客户10%+: 34%/27%/16%/10%", "超大规模云厂商+5G/MSO/MNO运营商"]','["Fabless模式，委托TSMC等代工", "使用成熟制程(n-1)，产能供应风险较低"]','1. Marvell Golden Cable正面竞争——更大研发预算($20亿+/年)和捆绑销售能力 2. CPO(共封装光学)可能在3.2T时代压缩AEC可寻址距离 3. 客户集中度仍高(34%依赖单一客户) 4. 估值30x+ P/S需持续高增长消化 5. FY24曾发生大客户砍单事件','数据中心连接芯片市场数十亿美元级别。AEC市场随800G→1.6T→3.2T每代翻倍增长。','{"item1": "Item 1. Business Company Overview At Credo, our mission is to redefine high-speed connectivity by delivering breakthrough solutions that enable the next generation of AI-driven applications. We are committed to enabling faster, more reliable, more energy-efficient, and scalable solutions that support the ever-expanding demands of AI, cloud computing and hyperscale networks. Our connectivity solutions are optimized for optical and electrical Ethernet and PCIe applications, including the 100G (or Gigabits per second), 200G, 400G, 800G and emerging 1.6T (or Terabits per second) ethernet markets and the 32G PCIe5 and upcoming 64G PCIe6 markets. Our products are based on our Serializer/Deserializer (SerDes) and Digital Signal Processor (DSP) technologies. Our product families include integrated circuits (ICs), Active Electrical Cables (AECs) and SerDes Chiplets. Our intellectual property (IP) solutions consist primarily of SerDes IP licensing. Data generation has increased dramatically over the past ten years, creating new and complicated challenges in both circuit and system design. Our proprietary SerDes and DSP technologies enable us to achieve similar performance to leading competitors’ products but at a lower cost and more highly available legacy node (n-1 advantage). Beyond power and performance, Credo continues to innovate to address customers’ system level requirements. We partner with Microsoft on our HiWire Switch AEC and open-source implementation that helps realize Microsoft’s vision for a highly reliable network-managed dual-Top-of-Rack (ToR) architecture (a network architecture design in which computing equipment located within the same or an adjacent rack are, for redundancy, connected to two in-rack network switches, which are, in turn, connected to aggregation switches via fiber optic cables), overcome complex and slow legacy enterprise approaches, simplify deployment and improve connection reliability in the data center. The multibillion-dollar data infrastructure market that we serve is driven largely by hyperscale data centers (hyperscalers), as well as general compute, AI/ML infrastructure, multi-service operators (MSOs) and mobile network operators (MNOs). The demands for increased bandwidth, improved power and cost efficiency and heightened security have simultaneously and dramatically expanded as work, education and entertainment have rapidly digitized across myriad endpoint users. We design, market and sell both product, software and IP solutions. We help define industry conventions and standards within the markets we target by collaborating with technology leaders and standards bodies. We contract with a variety of manufacturing partners to build our products based on our proprietary SerDes and DSP technologies. We develop standard solutions we can sell broadly to our end markets and also develop tailored solutions designed to address specific customer needs. Once developed, these tailored solutions can generally be broadly leveraged across our portfolio and we are able to sell the part or license the IP to the broader market. We have global sales, marketing and business development teams responsible for identifying and building our customer relationships. We sell our products to hyperscalers and cloud infrastructure providers, as well as MNO, MSO, 5G wireless, enterprise networking and high performance computing (HPC) customers. We are engaged with all of the major hyperscalers, and our customer base includes over 20 blue chip clients, including a broad mix of original equipment manufacturers (OEMs), original design manufacturers (ODMs), optical module manufacturers and other leading enterprises. During fiscal 2025 and 2024, we generated $436.8 million and $193.0 million in total revenue, respectively. Product sales and product engineering services revenue comprised 97% and 85% of our total revenue in fiscal 2025 and 2024, respectively, and IP license revenue represented 3% and 15% of our total revenue in fiscal 2025 and 2024, respectively. 8 Industry Overview We believe we are well positioned to benefit from the strong secular tailwinds driving the data infrastructure market, which is being driven by several factors, including: AI/ML Drives an Explosion in Network Traffic: Our hyperscale customers are increasingly pursuing AI/ML infrastructure that requires back end scale out interconnectivity densities that are an order or magnitude higher than their general compute infrastructure. The growth of AI/ML model sizes is driving an explosion in interconnectivity traffic which enables multiple physical devices to work on the same model at high speed and low latency. Credo provides Ethernet solutions to support this type of interconnectivity, and we believe that Ethernet has now become the standard for back end scale out networks. Back end scale up networks have grown from an appliance scale of 8 GPUs to rack scale of 72 GPUs in calendar 2024 and there is strong interest in growing this to ", "item1a": "Item 1A. Risk Factors Investors in our ordinary shares hold shares of a holding company incorporated as an exempted company under the laws of the Cayman Islands rather than equity securities of our subsidiaries that have substantive business operations. Credo Technology Group Holding Ltd is a holding company incorporated as an exempted company under the laws of the Cayman Islands with no operations of its own. We conduct substantially all of our operations through our indirect, wholly-owned subsidiaries in the United States and internationally. Investing in our ordinary shares involves a high degree of risk. You should carefully consider the risks and uncertainties described below, together with all of the other information in this filing, including our audited consolidated financial statements and related notes and “Management’s Discussion and Analysis of Financial Condition and Results of Operations,” before investing in our ordinary shares. If any of the following risks are realized, in whole or in part, our business, results of operations and financial condition could be materially and adversely affected. In that event, the price of our ordinary shares could decline, and you could lose part or all of your investment. Additional risks and uncertainties not presently known to us or that we currently deem immaterial also may impair the operation of our business. Risks Related to Our Business We depend on a limited number of customers for a substantial portion of our revenue. The loss of, or a significant reduction in sales to, one or more of our major customers could negatively impact our revenue and operating results. In fiscal 2025, we had one customer that accounted for 10% or more of our total revenue (such one customer accounting for 67% of total fiscal 2025 revenue). In addition, in fiscal 2025, sales to our top 10 customers accounted for approximately 90% of our total revenue. We believe our operating results for the foreseeable future will continue to depend on sales to a relatively small number of customers. In the future, these customers may decide not to purchase our products or solutions at all, may purchase fewer products or solutions than they did in the past or may alter their purchasing patterns. For example, in February 2023, we announced that our largest customer at the time reduced its demand forecast for certain of our products for reasons we understand were unrelated to our performance, which negatively impacted our fiscal 2023 fourth quarter revenue and our fiscal 2024 revenue expectations. Further, the amount of revenue attributable to any single customer or our general customer concentration, may fluctuate in any given period. In addition, our relationships with some customers may deter other potential customers who compete with these customers from buying our products. To attract new customers or retain existing customers, we may offer these customers favorable terms, including the right to terminate or delay orders on little notice, exclusivity or most favored nation pricing on our products. Such agreements could impair our operating results. In the event of pricing reductions or financial incentives for key customers, our average selling prices and gross margins would decline. The loss of a key customer, any reduction in sales to any key customer or our inability to attract new significant customers could negatively impact our revenue and materially and adversely affect our business or results of operations. We do not have long-term purchase commitments from our customers, and if our customers cancel or change their purchase orders, our revenue and operating results could suffer. Substantially all of our product sales to date have been made on a purchase order basis. We generally do not obtain long-term commitments with our customers or commitments for minimum purchases from our customers. Our arrangements with our customers permit our customers to cancel, change or delay their product purchase orders upon specified notice and subject to negotiated limitations. In some cases, our customers may cancel purchase orders on relatively short notice to us and without penalty to them. In addition, customers may delay delivery of orders to a subsequent fiscal quarter. Our revenue and operating results have, and could in the future, fluctuate materially and have, and could in the future, be materially and disproportionately impacted by the purchasing decisions of our customers, especially our larger customers. Our customers may decide to purchase fewer units than they have in the past, alter their purchasing patterns at any time with limited notice, change the terms on which they are prepared to do business with us or decide not to continue to purchase our products at all, any of which could cause our revenue to decline materially and materially harm our business, financial condition and results of operations. For example, in February 2023, we announced that that our largest customer reduc", "item7": "Item 7. Management’s Discussion and Analysis of Financial Condition and Results of Operations The following discussion and analysis of our financial condition and results of operations should be read in conjunction with the consolidated financial statements and related notes included elsewhere in this Annual Report on Form 10-K. This discussion contains forward-looking statements that involve risks and uncertainties. Our actual results could differ materially from those discussed in those forward-looking statements. Factors that could cause or contribute to such differences include those identified below and those discussed in the section titled “Risk Factors.” A discussion regarding our financial condition and our results of operations for the fiscal year ended May 3, 2025 compared to the fiscal year ended April 27, 2024 is presented below. A discussion regarding our results of operations for the fiscal year ended April 27, 2024 compared to the fiscal year ended April 29, 2023 can be found in “Management’s Discussion and Analysis of Financial Condition and Results of Operations” of our Annual Report on Form 10-K for the fiscal year ended April 27, 2024 , filed with the SEC on June 24, 2024. Overview At Credo, our mission is to redefine high-speed connectivity by delivering breakthrough solutions that enable the next generation of AI-driven applications. We are committed to enabling faster, more reliable, more energy-efficient, and scalable solutions that support the ever-expanding demands of AI, cloud computing and hyperscale networks. Our connectivity solutions are optimized for optical and electrical Ethernet and PCIe applications, including the 100G (or Gigabits per second), 200G, 400G, 800G and emerging 1.6T (or Terabits per second) ethernet markets and the 32G PCIe5 and upcoming 64G PCIe6 markets. Our products are based on our Serializer/Deserializer (SerDes) and Digital Signal Processor (DSP) technologies. Our product families include integrated circuits (ICs), Active Electrical Cables (AECs) and SerDes Chiplets. Our intellectual property (IP) solutions consist primarily of SerDes IP licensing. Data generation has increased dramatically over the past ten years, creating new and complicated challenges in both circuit and system design. Our proprietary SerDes and DSP technologies enable us to achieve similar performance to leading competitors’ products but at a lower cost and more highly available legacy node (n-1 advantage). Beyond power and performance, Credo continues to innovate to address customers’ system level requirements. We partner with Microsoft on our HiWire Switch AEC and open-source implementation that helps realize Microsoft’s vision for a highly reliable network-managed dual-Top-of-Rack (ToR) architecture (a network architecture design in which computing equipment located within the same or an adjacent rack are, for redundancy, connected to two in-rack network switches, which are, in turn, connected to aggregation switches via fiber optic cables), overcome complex and slow legacy enterprise approaches, simplify deployment and improve connection reliability in the data center. The multibillion-dollar data infrastructure market that we serve is driven largely by hyperscale data centers (hyperscalers), as well as general compute, AI/ML infrastructure, multi-service operators (MSOs) and mobile network operators (MNOs). The demands for increased bandwidth, improved power and cost efficiency and heightened security have simultaneously and dramatically expanded as work, education and entertainment have rapidly digitized across myriad endpoint users. We design, market and sell both product, software and IP solutions. We help define industry conventions and standards within the markets we target by collaborating with technology leaders and standards bodies. We contract with a variety of manufacturing partners to build our products based on our proprietary SerDes and DSP technologies. We develop standard solutions we can sell broadly to our end markets and also develop tailored solutions designed to address specific customer needs. Once developed, these tailored solutions can generally be broadly leveraged across our portfolio and we are able to sell the part or license the IP to the broader market. During fiscal 2025 and 2024, we generated $436.8 million and $193.0 million in total revenue, respectively. Product sales and product engineering services revenue comprised 97% and 85% of our total revenue in fiscal 2025 and 2024, respectively, and IP license revenue represented 3% and 15% of our total revenue in fiscal 2025 and 2024, respectively. Geographically, 15% and 31% of our total revenue in fiscal 2025 and 2024 was generated from customers in North America, and 85% and 69% of our total revenue in fiscal 2025 and 2024 was generated from customers in the rest of the world, primarily in Asia. During fiscal 2025 and 2024, we generated $52.2 million of net income and $28.4 million of net loss, res"}','deep_research','2025-07-02','2026-06-14T00:04:29');
INSERT INTO company_profiles VALUES('VICR','Vicor Corporation设计高密度电力转换模块，核心专利FPA(分解式电力架构)和VPD(垂直供电)。正从纯组件供应商转型为''电力层专利授权''模式——即使NVIDIA选用MPS/英飞凌，竞争者的垂直供电方案也可能需要Vicor专利授权。2025年收入$4.08亿，FY2026指引~$5.7亿(+40%)。','["DCM(DC-DC转换器) — 48V→1V GPU供电模块", "BCM(总线转换器)/PRM(调节器)/VTM(电压变压模块)", "FPA分解式架构 — 将供电拆为独立阶段提高效率", "VPD垂直供电 — PCB背面安装缩短供电路径", "专利授权/版税 — 新增收入来源"]','GPU供电socket: MPS占70-90%(GB200)/英飞凌为Vera Rubin主供/Renesas副供。VICR不是NVIDIA主供——但其VPD专利可能覆盖竞争者方案。2026.5新授权协议验证了这条路径。类似高通在手机基带的专利收费模式。','1. FPA/VPD专利覆盖面广——可能覆盖竞品的垂直供电方案 2. ChiP封装技术——高功率密度 3. 核心FPA专利~2022-23到期，但VPD/第5代续展专利延至2030s+ 4. 新全包授权协议验证''专利收费站''商业模式','["非NVIDIA主供——客户为其他AI芯片/服务器OEM", "新增: 未具名AI芯片厂商(专利授权)", "间接: 通过专利向MPS/英飞凌等竞争者收费"]','["自有制造(专有ChiP封装)", "不依赖外部代工"]','1. NVIDIA未采用VICR组件——缺少最大客户直接收入 2. 100x+ trailing P/E / $139亿市值 vs $5.7亿收入——极端估值 3. CEO 79岁(1981年创立)无继任计划——创始人依赖 4. 2025年卖$1.11亿股票(10b5-1,仍持26%) 5. 核心FPA专利已到期——依赖续展专利延续壁垒 6. MPS/英飞凌/Renesas研发预算10-50倍大','AI服务器功率模块市场$23亿(2025,Omdia)→$30亿(2029,CAGR 7.4%)。48V标准化扩大整体TAM。专利授权TAM难以量化但随AI GPU出货量线性增长。','{"item1": "ITEM 1. BUSINESS Overview We design, develop, manufacture, and market modular power components and power systems for converting electrical power (expressed as “watts,” and represented by the symbol “W”, with wattage being the product of voltage, expressed as “volts,” and represented by the symbol “V,” and current, expressed as “amperes,” and represented by the symbol “I”). In electrically-powered devices utilizing alternating current (“AC”) voltage from a primary AC source (for example, a wall outlet), a power system converts AC voltage into the stable direct current (“DC”) voltage necessary to power subsystems and/or individual applications and devices (known as “loads”). In many electronic devices, this DC voltage may be further converted to one or more voltages and currents required by a range of loads. In equipment utilizing DC voltage from a primary DC source (for example, a battery) or a secondary source (such as an AC-DC converter), the initial DC voltage similarly may require further conversion. A power system most commonly incorporates four voltage conversion functions: transformation, isolation, rectification, and regulation. 2 Table of Contents Transformation refers to the process of increasing or decreasing an AC voltage; isolation refers to the electrical separation, for safety, of primary and secondary voltages in a transformer; rectification refers to the process of converting a voltage from AC to DC and/or from DC to AC; and regulation refers to the process of providing a near constant voltage under a range of line and load conditions. Because numerous applications requiring different voltages, currents, and varied power ratings may exist within an electronically-powered device, and system power architectures themselves vary, we offer an extensive range of products and accessories in numerous application-specific configurations. We believe our product offering is among the most comprehensive in the market segments we serve. In addition to offering competitively differentiated products for sale, we also offer and engage in licensing arrangements with customers, resulting in royalty revenue. Our strategy, competitive positioning, and product offerings are all based on highly differentiated product performance, reflecting our anticipation of the evolution of system power architectures and customer performance requirements. Since the Company was founded, we have pursued continuous innovations in product design and achievements in product performance, largely enabled by our focus on the research and development of advanced technologies and processes, often implemented in proprietary semiconductor circuitry, materials, and packaging. Reflecting this strategy, we categorize our offerings as either “Advanced Products” or “Brick Products,” generally based on design, performance, and form factor considerations, as well as the range of evolving applications for which the products are appropriate. Our competition varies, depending on the market segment and application. Generally, we compete with developers and manufacturers of integrated circuits and semiconductor-based modules when addressing the needs of customers in enterprise computing and other market segments with implementations of our proprietary Factorized Power Architecture TM (“FPA”) using Advanced Products. In contrast, we generally compete with manufacturers of integrated power supplies when addressing the needs of customers, across a wide range of market segments, implementing conventional power systems architectures (e.g., Centralized Power Architecture (“CPA”), Distributed Power Architecture (“DPA”), and Intermediate Bus Architecture (“IBA”)) using Brick Products. Our website, www.vicorpower.com, sets forth detailed information describing our products, the applications for which they may be used, and our suite of design tools. The information contained on our website is not a part of, nor incorporated by reference into, this Annual Report on Form 10-K and shall not be deemed “filed” under the Securities Exchange Act of 1934, as amended (the “Exchange Act”). We are headquartered in Andover, Massachusetts, where our manufacturing facility is located. Our wholly-owned subsidiary, VICR Securities Corporation, also is located in Andover, Massachusetts. Our other domestic offices are located in Santa Clara, California, Lombard, Illinois, and Lincoln, Rhode Island. Our two Vicor Custom Power tm subsidiaries, Freedom Power Systems, Inc. and Northwest Power, Inc., are located in Cedar Park, Texas, and Milwaukie, Oregon, respectively. We have established individual subsidiaries or unincorporated branch offices outside of the United States, which we call Technical Support Centers (“TSCs”), to conduct preparatory and auxiliary services in support of the Company. Vicor Japan Company, Ltd. (“VJCL”), our 92.5%-owned Japanese subsidiary, which is engaged in sales and customer support activities exclusively for the sale of certain products customized by ", "item1a": "ITEM 1A. RISK FACTORS This Annual Report on Form 10-K contains forward-looking statements within the meaning of Section 27A of the Securities Act of 1933, as amended, and Section 21E of the Exchange Act. Actual results could differ materially from those projected in the forward-looking statements as a result of, among other factors, the risk factors set forth below. Operational Risks Our future operating results are difficult to predict and are subject to fluctuations. Our operating results, including revenues, gross margins, operating expenses, and net income (loss), have fluctuated on a quarterly and annual basis. Our strategic focus on higher volume opportunities with OEMs, ODMs, and contract 10 Table of Contents manufacturers has caused the actions of a relative few such customers to disproportionately influence our operating results. Unanticipated delays in purchase orders from, and shipments to, certain large customers have resulted in lower than expected revenue. Similarly, our strategic focus on the development of market-leading technologies and manufacturing processes, often implemented in proprietary semiconductor circuitry, materials, and packaging, has exposed the Company to the risks and costs of delays in such development and the use of a relatively few number of suppliers of proprietary circuits and materials or providers of proprietary services. Despite recent profitability trends, we cannot predict if we will maintain sustained profitability. Our future operating results may be materially influenced by a number of factors, many of which are beyond our control, including: • changes in demand for our products and for our customers’ end-products incorporating our products, as well as our ability to respond efficiently to such changes in demand, including changes in delivery lead times and the volume of product for which orders are accepted and the product shipped within an individual quarter; • our ability to manage our supply chain, inventory levels, and our own manufacturing capacity or that of third-party partners, particularly in the event of delays or cancellation of significant customer orders or in the event of delays or cost increases associated with our supply chain; • our ability to effectively coordinate changes in the mix of products we manufacture and sell, while managing our ongoing transition in organizational focus and manufacturing infrastructure to Advanced Products from Brick Products; • our ability to provide and maintain a high level of sales and engineering support to an increasing number of demanding, high volume customers; • the ability of our third party suppliers and service subcontractors to provide us sufficient quantities of high quality products, components, and/or services on a timely and cost-effective basis; • the effectiveness of our ongoing efforts to continuously reduce manufacturing costs per unit and manage operating expenses; • our ability to absorb and mitigate the impact of inflation on our operating results; • our ability to utilize our manufacturing facilities and personnel at efficient levels, maintaining sufficient production capacity and necessary manufacturing yields; • the timing of our new product introductions and our ability to meet customer expectations for timely delivery of fully qualified products; • the timing of new product introductions or other competitive actions (e.g., product price reductions) by our competitors; • the ability to hire, retain, and motivate qualified employees to meet the demands of our customers; • intellectual property disputes including disputes relating to the licensing of our intellectual property; • our ability to license our intellectual property; • litigation-related costs, which may be significant; • adverse economic conditions in the U.S. and those foreign countries in which we operate, as well as our ability to respond to unanticipated developments, such as the imposition of tariffs or trade restrictions; • adverse budgetary conditions within the U.S. government, particularly the Department of Defense, which continue to influence spending on current and anticipated programs into which we sell or anticipate to sell our products; • costs related to compliance with increasing worldwide governance, quality, environmental, and other regulations; • costs and consequences of disruption by third-parties of our global computer network and related resources; and • the effects of events outside of our control, including public health emergencies, natural disasters, terrorist activities, political risks, international conflicts, information security breaches, communication interruptions, and other force majeure . 11 Table of Contents As a result of these and other factors, we cannot assure you we will not experience significant fluctuations in future operating results on a quarterly or annual basis. In addition, if our operating results do not meet the expectations of investors, the market price of our Common Stock ma", "item7": "ITEM 7. MANAGEMENT’S DISCUSSION AND ANALYSIS OF FINANCIAL CONDITION AND RESULTS OF OPERATIONS Overview A discussion regarding our results of operations for the year ended December 31, 2024, compared to the year ended December 31, 2023, was included in the Company’s Annual Report on Form 10-K for the year ended December 31, 2024, on pages 24 and 26-28 under Part II, Item 7, “Management’s Discussion and Analysis of Financial Condition and Results of Operations”, which was filed with the SEC on March 3, 2025. We design, develop, manufacture, and market modular power components and power systems for converting electrical power for use in electrically-powered devices. Our competitive position is supported by innovations in product design and achievements in product performance, largely enabled by our focus on the research and development of advanced technologies and processes, often implemented in proprietary semiconductor circuitry, materials, and packaging. Many of our products incorporate patented or proprietary implementations of high-frequency switching topologies enabling power system solutions that are more efficient and much smaller than conventional alternatives. Our strategy emphasizes demonstrable product differentiation and a value proposition based on competitively superior solution performance, advantageous design flexibility, and a compelling total cost of ownership. While we offer a wide range of alternating current (“AC”) and direct current (“DC”) power conversion products, we consider our core competencies to be associated with 48V DC distribution, which offers numerous inherent cost and performance advantages over lower distribution voltages. However, we also offer products addressing other DC voltage standards (e.g., 380V for power distribution in data centers, 110V for rail applications, 28V for military and avionics applications, and 24V for industrial automation). Based on design, performance, and form factor considerations, as well as the range of evolving applications for which our products are appropriate, we categorize our product portfolios as either “Advanced Products” or “Brick Products.” The Advanced Products category consists of our more recently introduced products, which are largely used to implement our proprietary Factorized Power Architecture™ (“FPA”), an innovative power distribution architecture enabling flexible, rapid power system design using individual components optimized to perform a specific conversion function. The Brick Products category largely consists of our broad and well-established families of integrated power converters, incorporating multiple conversion stages, used in conventional power systems architectures. Given the growth profiles of the markets we serve with our Advanced Products line and our Brick Products line, our strategy involves a continuing transition in organizational focus, emphasizing investment in our Advanced Products line and targeting high growth market segments with a low-mix, high-volume operational model, while maintaining a profitable business in the mature market segments we serve with our Brick Products line with a high-mix, low-volume operational model. The applications in which our Advanced Products and Brick Products are used are typically in the higher-performance, higher-power segments of the market segments we serve. With our Advanced Products, we generally serve large Original Equipment Manufacturers (“OEMs”), Original Design Manufacturers (“ODMs”), and their contract manufacturers, with sales currently concentrated in the data center and hyperscaler segments of enterprise computing, in which our products are used for power delivery on server motherboards, in server racks, and across datacenter infrastructure. We have established a leadership position in the emerging market segment for powering high-performance processors used for acceleration of applications associated with artificial intelligence (“AI”). Our customers in the AI market segment include the leading innovators in processor and accelerator design, as well as early adopters in cloud computing and high performance computing. We also serve applications in aerospace and aviation, defense electronics, satellites, factory automation, instrumentation, test equipment, transportation, telecommunications and networking infrastructure, and vehicles (notably in the autonomous driving, electric vehicle, and hybrid vehicle niches of the vehicle segment). With our Brick Products, we generally serve a fragmented base of large and small customers, concentrated in aerospace and defense electronics, industrial equipment, instrumentation and test equipment, and transportation (notably in rail and heavy equipment applications). With our strategic emphasis on larger, high-volume customers, we expect to experience over time a greater concentration of sales, including from intellectual property licensing among relatively fewer customers. Our quarterly consolidated operating results ca"}','deep_research','2026-03-02','2026-06-14T00:04:29');
INSERT INTO company_profiles VALUES('ADEA','Adeia Inc是纯IP授权公司，两个业务: 媒体IP(~94%收入,视频/流媒体专利)和半导体IP(~6%,$2600万,DBI混合键合专利)。FY2025收入$4.43亿(+18% YoY)。EBITDA利润率60-73%。市值~$34亿。DBI是混合键合核心专利——HBM4和3D chiplet的未来标准。','["DBI(Direct Bond Interconnect)混合键合专利授权", "媒体IP — 视频传输/流媒体/电子节目指南专利", "授权模式: 多年固定费+版税", "不制造任何产品——纯IP货币化"]','混合键合专利三强: TSMC(工艺专利)/Adeia(基础DBI专利)/YMTC(中国)。Adeia的DBI专利覆盖Cu-Cu直接键合基础工艺——AMD试图绕过但诉讼失败后签约。TSMC虽有自研专利，部分工艺仍需Adeia授权。','1. ~11500项专利组合(DBI基础专利源自Ziptronix,2000年代) 2. 基础性(非衍生)专利——覆盖混合键合核心工艺 3. AMD诉讼和解+授权(2026 Q1)——验证法律可执行性 4. 已授权: TSMC/ST/UMC/Canon/Sony/AMD 5. 半导体IP订单翻倍增长中','["媒体: Google/Disney/微软/主要Pay-TV运营商", "半导体: ST Micro/UMC/AMD/Canon/Sony", "下一波目标: Broadcom/Qualcomm等逻辑chiplet设计商"]','["无——纯IP公司，无制造/供应链"]','1. 半导体IP仅6%收入——AI主题是小基数赌注 2. 媒体IP面临剪线压力(Pay-TV下滑) 3. 专利可能被IPR挑战无效化 4. TSMC/YMTC有自研混合键合专利——不完全依赖Adeia 5. CEO计划2026离职——领导层过渡风险 6. 半导体IP需从6%增长到20%+才能重新定价为AI概念','半导体IP授权TAM: 当前~$2600万→2030年预估>$2亿。HBM4+逻辑chiplet全面采用混合键合是TAM拐点。','{"item1a": "Item 1A. Risk Factors – “Our systems, networks and business activities and those of third parties that we utilize in our operations are subject to cybersecurity and stability risks, including information technology system failures, and security breaches.” We engage third-party assessors to conduct penetration testing and measure our program to industry standard frameworks. We also have standing engagements with incident response experts and external counsel. Our information technology team led by our Vice President of Information Technology (VP of IT) frequently collaborates with industry experts and cybersecurity practitioners at other companies to exchange information about potential cybersecurity threats, best practices, and industry trends. Our cybersecurity risk management extends to risks associated with our use of third-party service providers. We routinely conduct risk and compliance assessments of third-party service providers that request access to our information assets. We re-assess our third-party vendors on an ongoing basis. Our cybersecurity risk management is integrated into our comprehensive business continuity program and enterprise risk management. Our information technology team periodically engages with a cross-functional group of subject matter experts and leaders to assess and refine our cybersecurity risk posture and preparedness. 24 Governance of Cybersecurity Risk Management The Board of Directors, as a whole, has oversight responsibility for our strategic and operational risks. The Board of Directors has delegated to the audit committee the responsibility of reviewing and discussing our risk assessment and risk management practices, including cybersecurity risks, with members of management. The audit committee, in turn, regularly reports on its review with the Board of Directors . Management is responsible for day-to-day implementation of risk management strategies and recommends process improvements. Our VP of IT has primary oversight of material risks from cybersecurity threats. Our VP of IT has more than 25 years of experience across various engineering, business and management roles focused on information technology, including roles at global, public companies, as well as across multiple industries including fintech, research, and high tech. Our VP of IT regularly presents updates to the audit committee regarding Company cybersecurity matters and developing industry trends. We have retained an outside cybersecurity firm for our managed security services, which reports to our VP of IT. The cybersecurity firm has professionals with more than 20 years of experience working in information technology-related roles and degrees in Information Technology, including cybersecurity, Certified in Risk and Information Systems Control (CRISC), and Global Information Assurance Certifications in Security Essentials (GSEC) as an Intrusion Analyst (GCIA). The cybersecurity firm has extensive experience in supporting firms in applied knowledge of information technology governance and security frameworks that include, for example: ISO 27000, NIST, HITRUST, ISC2, ITIL, and COBIT. Management assesses our cybersecurity readiness through internal assessment tools as well as third-party control tests, vulnerability assessments, audits and regular evaluation against industry standards. We have governance and compliance structures that are designed to elevate issues relating to cybersecurity to management and the audit committee, such as potential threats or vulnerabilities. We also employ various defensive and continuous monitoring techniques using recognized industry frameworks and cybersecurity standards. Our VP of IT meets with the audit committee quarterly to review our information technology systems and discuss key cybersecurity risks, and these matters are also presented to the Board of Directors annually. In addition, our chief financial officer reviews with the audit committee, at least annually, our global enterprise risk management program, which includes cybersecurity risks, and is also reported to the Board of Directors. Item 2. Pr operties We lease our 62,000 square foot corporate headquarters, which houses our administrative, sales, marketing and research and development facilities, in San Jose, California. We also lease another office building with approximately 5,336 square feet in Burbank, California to house additional administrative, sales, and marketing personnel. Further, we also lease another facility in the Morrisville, North Carolina with approximately 2,737 square feet. We believe that our existing space is adequate for our current operations and that suitable replacement and additional space, to the extent needed, will be available in the future on commercially reasonable terms. Item 3. Legal Proceedings In the normal course of our business, we are involved in legal proceedings. In the past, we have litigated to enforce our patents and other intellectual property rights (“IP”)", "item7": "Item 7. Management’s Discussion and Analysis of Financial Condition and Results of Operations The following discussion is intended to promote understanding of the results of operations and financial condition and should be read in conjunction with our consolidated financial statements and notes thereto. This section of this Form 10-K generally discusses 2025 and 2024 items and year-to-year comparisons of 2025 against 2024. A discussion regarding 2023 items and year-to-year comparisons of 2024 against 2023 can be found in “Management’s Discussion and Analysis of Financial Condition and Results of Operations” in Part II, Item 7 of our Annual Report on Form 10-K for the fiscal year ended December 31, 2024. The following discussion of our financial condition and results of operations should be read together with the audited consolidated financial statements and notes to the consolidated financial statements included elsewhere in this Form 10-K. This discussion contains forward-looking statements that involve risks and uncertainties. The forward-looking statements are not historical facts, but rather are based on current expectations, estimates, assumptions and projections about our industry, business and future financial results. Our actual results could differ materially from the results contemplated by these forward-looking statements due to a number of factors, including those discussed under “Risk Factors” in Part I, Item 1A above. Business Overview Adeia Inc. (formerly known as Xperi Holding Corporation) (“Adeia”, “we”) is a leading IP licensing platform in the consumer and entertainment space, with an extensive portfolio of media and semiconductor intellectual property and approximately 13,750 media and semiconductor patent assets worldwide. In order to serve an increasingly connected world, we invent, develop, and license fundamental innovations that enhance billions of devices and shape the way millions of people explore and experience entertainment. Our inventions are key enabling technologies that drive how consumers interact with entertainment and devices at home and on the go around the world. Our foundational technologies help elevate content and improve how audiences connect with it in a way that is more intelligent, immersive and personal. Our innovative solutions help power smart devices, entertainment experiences and more, and have created a unified ecosystem that reaches highly-engaged consumers and uncovered new business opportunities. Headquartered in Silicon Valley with more than 35 years of operating experience, we have approximately 150 full-time employees, with substantially all of our employees located in the U.S. Macroeconomic Conditions Macroeconomic conditions due to inflation, geopolitical instability and global health events have in the past, and may in the future have, an adverse impact on our business. For example, such conditions may cause volatility in the markets we serve, particularly the broad consumer electronics market. Impacts from adverse macroeconomic conditions may negatively impact our financial condition and results of operations, which could result in an impairment of our long-lived assets, including goodwill, and increased credit losses. Although a significant portion of our revenue is derived from fixed-fee and minimum-guarantee arrangements from large, well-capitalized customers, our per-unit and variable-fee based revenue will continue to be susceptible to global health concerns, outbreaks, pandemics, armed conflict, geopolitical factors, trade regulations and tariffs, market volatility, labor shortages, supply chain disruptions, microchip shortages, changes in demand for semiconductors and market downturns. Reportable Segments We operate and report in one segment: IP Licensing. We believe that this structure reflects our current operational and financial management and provides the best structure for us to focus on growth opportunities. Our Chief Executive Officer has been determined to be the Chief Operating Decision Maker (“CODM”) in consideration with the authoritative guidance on segment reporting. We primarily license our innovations to leading companies in the broader media entertainment and semiconductor industries, and those companies developing new technologies that will help drive these industries forward. Licensing arrangements include access to one or more of our foundational patent portfolios and may also include access to some portions of our industry-leading technologies and know-how. 31 Key Metrics In evaluating our financial condition and operating performance, we primarily focus on revenue and cash flows from operations. For the year ended December 31, 2025, as compared to the same period in 2024: • Revenue increased by $67.4 million, or 18%, from $376.0 million in 2024 to $443.4 million in 2025. • Recurring revenues increased by $9.8 million, or 3% from $341.5 million in 2024 to $351.3 million in 2025. • Non-recurring revenues increased by $5"}','deep_research','2026-02-26','2026-06-14T00:04:29');
INSERT INTO company_profiles VALUES('MX','MagnaChip Semiconductor是韩国功率半导体公司(已退出OLED DDIC业务)。主要产品功率MOSFET和IGBT，服务智能手机/电视/工业/汽车市场。Q1 2026收入$4620万。毛利率15.6%。持续亏损。市值$2.28亿。0.86x P/B——市场将其视为价值/重组标的。','["功率MOSFET(低压/中压/超级结) — 90%收入", "IGBT/SiC(新兴)", "Power IC — TV-LED/OLED功率管理(10%收入)", "注: OLED DDIC业务已关停"]','完全商品化市场，全球份额微乎其微。竞争者: 英飞凌/安森美/ST/Vishay/Nexperia+数十家中国/台湾厂商。MX毛利率15.6% vs 英飞凌45%说明一切——零定价权。','无显著技术壁垒。功率MOSFET是成熟技术，进入门槛低。MX有Gumi自有晶圆厂(正从代工转型为自产)，但这是成本因素非技术壁垒。','["韩国/中国OEM/ODM(智能手机/电视)", "工业/汽车客户", "无超大规模云厂商/AI客户"]','["Gumi自有晶圆厂", "外部代工(部分)"]','1. 持续亏损——无明确盈利路径 2. 毛利率15.6%——深度商品化/零定价权 3. 中国ASP持续侵蚀 4. $4230万债务2027.3到期+$5000万Shelf=稀释风险 5. 与AI产业链无实质关联——AI服务器MOSFET是商品市场','全球功率MOSFET市场约$100亿+/年。AI服务器PSU MOSFET $23亿(2025)→$30亿(2029)。但MX在其中份额微乎其微。','{"item1": "Item 1. Business—Executive Officers of the Company.” The other information required by this item is incorporated by reference to our definitive proxy statement relating to our 2026 annual meeting of stockholders or will be included by amendment to this Report within 120 days after the end of the fiscal year to which this Report relates. Insider Trading Policy We have adopted an insider trading policy (“Securities Trading Policy”) governing the purchase, sale and/or other dispositions of the Company’s securities by the Company’s directors, officers and employees, among other covered persons. The Company believes this policy is reasonably designed to promote and enforce compliance by such covered persons with applicable insider trading laws, rules and regulations, and the listing standards applicable to the Company. A copy of our Securities Trading Policy is filed as Exhibit 19.1 to this Annual Report on Form 10-K. Ite m 11. Executive Compensation The information required by this item is incorporated by reference to our definitive proxy statement relating to our 2026 annual meeting of stockholders or will be included by amendment to this Report within 120 days after the end of the fiscal year to which this Report relates. It em 12. Security Ownership of Certain Beneficial Owners and Management and Related Stockholder Matters The information required by this item is incorporated by reference to our definitive proxy statement relating to our 2026 annual meeting of stockholders or will be included by amendment to this Report within 120 days after the end of the fiscal year to which this Report relates. Ite m 13. Certain Relationships and Related Transactions, and Director Independence The information required by this item is incorporated by reference to our definitive proxy statement relating to our 2026 annual meeting of stockholders or will be included by amendment to this Report within 120 days after the end of the fiscal year to which this Report relates. It em 14. Principal Accounting Fees and Services. The information required by this item is incorporated by reference to our definitive proxy statement relating to our 2026 annual meeting of stockholders or will be included by amendment to this Report within 120 days after the end of the fiscal year to which this Report relates. 90 Table of Contents P ART IV Ite m 15. Exhibits and Financial Statement Schedules 1. Financial Statements The information required by this item is included in Item 8 of Part II of this Report. 2. Financial Statement Schedules Financial Statement Schedules are omitted because of the absence of the conditions under which they are required or because the information required by such omitted schedules is set forth in the financial statements or the notes thereto. 3. Exhibits Exhibit No. Exhibit Description 2.1 Business Transfer Agreement, dated as of March 31, 2020 among by and among Magnus Semiconductor, LLC, MagnaChip Semiconductor S.A. and MagnaChip Semiconductor, Ltd. (incorporated by reference to Exhibit 10.1 to our Current Report on Form 8-K filed on March 31, 2020). 3.1 Certificate of Conversion of MagnaChip Semiconductor LLC (incorporated by reference to Exhibit 3.1 to our Current Report on Form 8-K filed on March 11, 2011). 3.2 Certificate of Incorporation of MagnaChip Semiconductor Corporation (incorporated by reference to Exhibit 3.2 to our Current Report on Form 8-K filed on March 11, 2011). 3.3 Certificate of Amendment to the Certificate of Incorporation of Magnachip Semiconductor Corporation (incorporated by reference to Exhibit 3.1 to our Current report on Form 8-K filed on December 30, 2020). 3.4 Amended and Restated Bylaws of MagnaChip Semiconductor Corporation (incorporated by reference to Exhibit 3.1 to our Current Report on Form 8-K filed on May 6, 2016). 3.5 Form of Plan of Conversion of MagnaChip Semiconductor LLC (incorporated by reference to Exhibit 3.6 to our Amendment No. 2 to Registration Statement on Form S-1 filed on May 11, 2010 (Registration No. 333-165467)). 3.6 Certificate of Designation, Preferences and Rights of Series A Junior Participating Preferred Stock of MagnaChip Semiconductor Corporation, as filed with the Secretary of the State of Delaware on March 6, 2015 (incorporated by reference to Exhibit 3.1 to our Current Report on Form 8-K filed on March 6, 2015). 3.7 Certificate of Designation of Series A-1, Junior Participating Preferred Stock of Magnachip Semiconductor Corporation, as filed with the Secretary of State of Delaware on December 13, 2021. 4.1 Description of Securities (incorporated by reference to Exhibit 4.1 to our Annual Report on Form 10-K filed on March 14, 2025). 10.1 Intellectual Property License Agreement, dated as of October 6, 2004, by and between Hynix Semiconductor Inc. and MagnaChip Semiconductor, Ltd. (Korea) (incorporated by reference to Exhibit 10.2 to our Amendment No. 1 to Registration Statement on Form S-1 filed on April 20, 2010 (Registration No. 333-165467)). 10.2* M", "item1a": "Item 1A. Risk Factors” in this Report for additional information. Ite m 4. Mine Safety Disclosures Not applicable. 31 Table of Contents PA RT II It em 5. Market for Registrant’s Common Equity, Related Stockholder Matters and Issuer Purchases of Equity Securities Market Information Our common stock is listed on the New York Stock Exchange under the symbol “MX.” Total Return to Stockholders (Including Reinvestment of Dividends) Indexed Returns Company/Index Base Period 12/31/2020 12/31/2021 12/30/2022 12/29/2023 12/31/2024 12/31/2025 Magnachip Semiconductor Corporation 100 155.10 69.45 55.47 29.73 18.86 S&P 500 Index 100 126.89 102.22 126.99 156.59 182.25 Philadelphia Semiconductor Index 100 141.16 90.58 149.36 178.14 253.38 Holders The approximate number of record holders of our outstanding common stock as of February 28, 2025 was 66. This number does not include beneficial owners for whom shares are held by nominees in street name. Stock-Based Compensation For information on securities authorized for issuance under our equity compensation plans, see Item 12. Security Ownership of Certain Beneficial Owners and Management and Related Stockholder Matters. Dividends We have not historically paid any cash dividends on our common stock. Our Board of Directors continuously evaluates our capital allocation strategy and liquidity targets, but has not currently implemented any dividend or distribution policy. Any determination to pay dividends in the future will be at the discretion of our Board of Directors. Issuer Purchases of Equity Securities The following table shows the monthly activity related to our repurchases of common stock for the quarter ended December 31, 2025. Period Total Number of Shares Purchased Average Price Paid per Share Total Number of Shares Purchased as Part of Publicly Announced Plans or Programs(2) Approximate dollar value of Shares that may yet be Purchased under the Plans or Programs (in thousands)(2) October 2025(1) 13,500 $ 3.02 — $ 20,951 November 2025(1) 274 $ 3.10 — $ 20,951 December 2025(1) 68,988 $ 2.55 — $ 20,951 Total 82,762 $ 2.63 — $ 20,951 (1) Represents shares withheld to satisfy tax withholding obligations in connection with the vesting of restricted stock units issued under our equity incentive plans. (2) On July 19, 2023, the Company’s Board of Directors authorized a new $50 million stock buyback program (the \"Repurchase Plan\"). Purchases under the Repurchase Plan have been and will be made in the open market or through privately negotiated transactions, depending upon market conditions and other factors. No purchases under the Repurchase Plan were made during the quarter ended December 31, 2025. It em 6. [Reserved] 32 Table of Contents It em 7. Management’s Discussion and Analysis of Financial Condition and Results of Operations The following discussion and analysis should be read in conjunction with the audited consolidated financial statements, together in each case with the related notes, included elsewhere in this Report. This discussion and analysis contains, in addition to historical information, forward-looking statements that include risks and uncertainties. Our actual results may differ materially from those anticipated in these forward-looking statements as a result of certain factors, including those set forth under the heading “Risk Factors” and elsewhere in this Report. We have reclassified certain prior year amounts to conform to the current year’s presentation for discontinued operations, reflecting the shutdown of the Display business and transition into a pure-play Power company. Unless otherwise stated, information in this section relates to our continuing operations. The consolidated statements of cash flows have not been adjusted to separately disclose cash flows related to discontinued operations. Overview We are a designer and manufacturer of analog and mixed-signal power semiconductor platform solutions for various applications, including industrial, automotive, communication, consumer and computing. We have a proven record with about 45 years of operating history, a portfolio of more than 950 registered patents and pending applications and extensive engineering and manufacturing process expertise. We develop and manufacture Power Analog Solutions products and develop Power integrated circuit (“IC”) products. Power Analog Solutions products include metal oxide semiconductor field effect transistors (“MOSFETs”) and insulated-gate bipolar transistors (“IGBTs”) for a range of devices, including televisions, smartphones, mobile phones, wearable devices, desktop PCs, notebook PCs, tablet PCs, home appliance, other consumer electronics, automotive and industrial applications such as power suppliers, e-bikes, photovoltaic inverters, LED lighting and motor drives. Our Power IC products provide Power IC solutions to major television suppliers and large panel display suppliers. These products include AC-DC/DC-DC converters, LED drivers, regulators, power mana", "item7": "Item 7. Management’s Discussion and Analysis of Financial Condition and Results of Operations—Factors Affecting our Results of Operations” for further details. The loss of our key employees would materially adversely affect our business, and we may not be able to attract or retain the technical or management employees necessary to compete in our industry. Our key executives have substantial experience and have made significant contributions to our business, and our continued success is dependent upon the retention of our key management executives. The loss of such key personnel would have a material adverse effect on our business. In addition, our future success depends on our ability to attract and retain skilled technical and managerial personnel. We do not know whether we will be able to retain all of these employees as we continue to pursue our business strategy. The loss of the services of key employees, especially our key design and technical personnel, or our inability to retain, attract and motivate qualified design and technical personnel, could have a material adverse effect on our business, financial condition and results of operations. This could hinder our research and product development programs or otherwise have a material adverse effect on our business. If we encounter future labor problems, we may fail to deliver our products and services in a timely manner, which would adversely affect our revenues and profitability. As of December 31, 2025, 441 employees, or approximately 64% of our employees, were represented by the Magnachip Semiconductor Labor Unions. We can offer no assurance that any issues with the labor union and other employees will be resolved favorably for us in the future, that we will not experience work stoppages or other labor problems in future years or that we will not incur significant expenses related to such issues. 18 Table of Contents We may incur costs to engage in future business combinations or strategic investments, and we may not realize the anticipated benefits of those transactions. As part of our business strategy, we may seek to enter into business combinations, investments, joint ventures and other strategic alliances with other companies in order to maintain and grow revenue and market presence as well as to provide us with access to technology, products and services. Any such transaction would be accompanied by risks that may harm our business, such as difficulties in assimilating the operations, personnel and products of an acquired business or in realizing the projected benefits, disruption of our ongoing business, potential increases in our indebtedness and contingent liabilities and charges if the acquired company or assets are later determined to be worth less than the amount paid for them in an earlier original acquisition. In addition, our indebtedness may restrict us from making acquisitions that we may otherwise wish to pursue. The failure to achieve acceptable manufacturing yields could adversely affect our business. The manufacturing of semiconductors involves highly complex processes that require precision, a highly regulated and sterile environment and specialized equipment. Defects or other difficulties in the manufacturing process can prevent us from achieving acceptable yields in the manufacturing of our products, which could lead to higher costs, a loss of customers or delay in market acceptance of our products. Slight impurities or defects in the photomasks used to print circuits on a wafer or other factors can cause significant difficulties, particularly in connection with the production of a new product, the adoption of a new manufacturing process or any expansion of our manufacturing capacity and related transitions. We may also experience manufacturing problems in achieving acceptable yields as a result of, among other things, transferring production to other facilities, upgrading or expanding existing facilities or changing our process technologies. Yields below our target levels can negatively impact our gross profit and may cause us to eliminate underperforming products. We rely on a number of independent subcontractors and the failure of any of these independent subcontractors to perform as required could adversely affect our operating results. A substantial portion of our net sales are derived from semiconductor devices assembled in packages or on film. The packaging and testing of semiconductors require technical skills and specialized equipment. For the portion of packaging and testing that we outsource, we use subcontractors located in Korea and China. We rely on these subcontractors to package and test our devices with acceptable quality and yield levels, and, while we specify quality standards, we are not able to directly oversee their day-to-day operations and the packaging and testing of our devices. Onboarding of a new subcontractor, including as a result of switching from one subcontractor to another, takes approximatel"}','deep_research','2026-03-16','2026-06-14T00:04:29');
INSERT INTO company_profiles VALUES('NNE','Nano Nuclear Energy开发便携式微型核反应堆(1-20 MWe)——ZEUS(固体堆芯)/ODIN(低压冷却剂)/KRONOS MMR(高温气冷)。2026年6月收购HALEU运输公司(Secured Transportation Services)。零收入。$5.7亿现金。市值~$12亿。分析师预测2029年收入~$460万。','["ZEUS固体堆芯微反应堆(概念阶段)", "ODIN低压冷却剂反应堆(概念阶段)", "KRONOS MMR高温气冷反应堆(NRC申请审查中)", "HALEU运输/物流(收购获得，少量收入)"]','50+家美国公司开发先进反应堆(NNSA数据)。主要竞争者: Oklo(Sam Altman支持,$10亿+融资)/Westinghouse eVinci(工业巨头)/Radiant(DOE资助)/X-energy(DOE示范项目)/TerraPower(比尔盖茨)。NNE无技术/资金/客户优势。','无——反应堆仅存在于纸面。NRC建设许可申请刚被接受审查(起步阶段)。HALEU运输NRC/DOT许可是唯一具体资质但TAM极小。无运行反应堆=无技术验证。','["无付费客户", "与Super Micro Computer探讨核电方案(概念阶段)", "超大客户(微软/谷歌/亚马逊)均选择更成熟的设计"]','["HALEU燃料需来自Centrus(美国唯一来源)", "反应堆制造/组件——未确定供应链"]','1. 零收入/$12亿市值——260x 2029年预测收入 2. NRC完整许可5-10年——极长周期 3. 50+竞争者更有资金和技术背景 4. 烧钱加速(Q2亏损$920万,+48% vs Q1) 5. 超大客户选择成熟设计非初创概念 6. 反应堆仅存在于纸面——无技术验证','微型反应堆市场长期潜力大(AI数据中心核电化)，但商业化在2030s。NNE在其中无确定份额。','{"item1": "ITEM 1. Business - Arrangements with Our Executive Officers.” The following table provides a breakdown of our staff by function as of December 16, 2025. Function Number of Staff % of Total Management 8 12.9 % Research and Development (1) 21 33.9 % Business Operation (2) 31 50.0 % Administration 2 3.2 % Total 62 100 % (1) There was an increase of headcounts for a total of five staff, or approximately 31% of the total research and development personnel in the research and development department in 2025 compared to the same period in 2024. The above-mentioned increases were due to the recruitment of new staff for our research and development. (2) There was an increase of headcounts for a total of ten staff, or approximately 48% of the business operation personnel in the business operation department in 2025 compared to the same period in 2024. The above-mentioned increases were due to the recruitment of new staff for our business operations. Our workforce operates under a hybrid model that integrates both in-office and remote work arrangements. Our management team places significant focus and attention on matters concerning our human capital assets, particularly on the specific industry and technical knowledge that are required to implement our nuclear energy-focused business plan. Accordingly, we regularly review staff development and succession plans for each of our functions to identify and develop our pipeline of talent. 25 We believe we offer our staff competitive compensation packages and an environment that encourages self-development and, as a result, have generally been able to attract and retain qualified personnel and maintain a stable core management team. Our staff are not represented by a labor organization or covered by a collective bargaining agreement. We believe that we maintain a good working relationship with our staff and to date, we have not experienced any labor disputes. Description of Properties Our corporate headquarters is located at 10 Times Square, 30th Floor, New York, New York 10018, covering approximately 7,800 square feet. We lease this space for $33,605 per month whereby the monthly lease rent will increase by 2.5% on an annual basis. The lease is effective on April 1, 2024 and has a term ending on July 31, 2031. In August 2024, we purchased a 1.64-acre land package in the historic Heritage Center Industrial Park in Oak Ridge, Tennessee for $1.7 million. The purchase includes a 14,000 sq. ft., 2-story building to house our Nuclear Technology Branch. Situated in a world-class location for innovative nuclear technology research and development, this facility will serve as the central hub for our advanced nuclear technology design and engineering capabilities. The Nuclear Technology Branch is near the Oak Ridge National Laboratory, the Spallation Neutron Source, the National Transportation Research Center, and The University of Tennessee’s Center of Excellence in Engineering. In January 2025, we entered into a lease for a facility of approximately 6,800 sq. ft. in Westchester County, New York, where we have established a purpose-built facility to assemble and demonstrate the operation and viability of several non-nuclear parts and components of our nuclear microreactors in development. We lease this space for $17,000 per month whereby the monthly lease rent will increase by 2.5% on an annual basis. The lease is effective on January 1, 2025 and has a term ending on December 30, 2030. In July 2025, we purchased a 2.75-acre land package in Oak Brook, Illinois for $3.5 million. The purchase included a 23,537 sq. ft. building to serve as a regional demonstration and office facility to support the development of our KRONOS MMR™ Microreactor Energy System. We believe the above-mentioned facilities and offices are adequate and suitable for our current needs and that, should it be needed, suitable additional or alternative space will be available to accommodate any such expansion of our operations. Corporate History and Corporate Structure We were incorporated under the laws of the State of Nevada on February 8, 2022. We are primarily engaged in the design and development of mobile, easily deployable microreactors, the development of a commercial CAT II facility for fuel processing, and the creation of a commercial transportation technology and business, with the capacity to move fuel enriched up to 19.75% U235 across North America. HALEU Energy Fuel Inc. (which we refer to herein as HALEU Energy), incorporated on August 30, 2022 under the laws of Nevada, is our wholly-owned subsidiary. Through HALEU Energy, we are seeking to develop a domestic HALEU fuel processing facility to supply the next generation of advanced nuclear reactors. American Uranium Inc. (which we refer to herein as American Uranium), incorporated on February 9, 2022 under the laws of Nevada, is our wholly-owned subsidiary. Through American Uranium, we are engaged in the acquisition, exploration and development of uraniu", "item1a": "ITEM 1A. Risk Factors Investing in our securities is speculative and involves a high degree of risk . You should carefully consider the risks and uncertainties described below, together with all of the other information contained in this Report, before deciding to invest in our securities. If any of the following risks materialize, our business, financial condition, results of operation and prospects will likely be materially and adversely affected. In that event, the market price of our common stock could decline, and you could lose all or part of your investment. Risks Related to Our Industry and Business We have incurred losses and have not generated any revenue since our inception. We anticipate that we will continue to incur losses, and expect that we will not generate meaningful revenue for the foreseeable future. We have incurred significant operating losses since inception and have an accumulated deficit of $57.5 million as of September 30, 2025 and had negative operating cash flow for the year ended September 30, 2025. We expect that operating losses and negative cash flows will increase in the coming years because of additional costs and expenses related to our research and development (which we refer to herein as R&D), business development activities and our status as a publicly traded company. To date, we have not generated any revenue. We do not expect to generate any revenue unless and until we are able to commercialize our reactors and/or other lines of business. As we have incurred losses and experienced negative operating cash flows since our inception, and accordingly we have undertaken equity financing from investors to satisfy our funding needs, and we will consider applications for government grants; however, we may not raise adequate funding to offset our expenses and losses. Moreover, we may encounter unforeseen expenses, difficulties, complications, delays, and other unknown factors that may adversely affect our business. The magnitude of our future net losses will depend, in part, on the rate of future growth of our expenses and our ability to generate and grow revenue. We cannot predict the outcome of the actions to generate liquidity to fund our operations, whether such actions would generate the expected liquidity to fund our operations as currently planned or whether the costs of such actions will be available on reasonable terms or at all. Our continued solvency is dependent upon our ability to obtain additional working capital to complete our reactor development, to successfully market our reactors and to achieve commerciality for our reactors. Our prior losses and expected future losses have had and may continue to have adverse effects on our stockholders’ equity (deficit) and working capital and may lead to the failure of our business. 27 We are a pre-revenue company in an emerging market with an unproven business model, new and unproven technologies, and a short operating history, which makes it difficult to evaluate our current business and prospects and may increase the risk of your investment. We only have a limited operating history upon which to base an evaluation of our current and future business prospects. We were founded in February 2022 and are currently in the process of developing our nuclear microreactors and other lines of business as more fully described in the “ Business ” section of this Report. We anticipate that it will take several years for us to commence generating meaningful revenues. Moreover, we will be required to make significant expenditures over the near and long term just to achieve any level of revenues. Over the next twelve months, we will continue to progress the development of our advanced microreactors and our vertically integrated fuel processing business, with estimated expenditures to be approximately $65 million. This allocation comprises approximately $43 million dedicated to the research, development, quality assurance, licensing, and physical test work of our microreactors and other technologies, such as our fuel transportation system. A further allocation of approximately $12 million will be allocated to the development of our planned fuel processing facilities alongside LIST, the related-party uranium enrichment company with whom we collaborate and in which we’ve made a strategic investment. The remaining approximate $10 million is earmarked for miscellaneous costs essential to propelling the progress of our microreactors, encompassing the support of current personnel engaged in executive, finance, accounting, and other administrative functions. We may also utilize our cash resources raised in 2024 and 2025 for acquisitions of complementary businesses or assets. We estimate that the development, construction, testing and licensing of our microreactors (notably the KRONOS MMR) will continue from 2026 to 2030, with the full-scale, first-of-its-kind KRONOS energy system expected to be fully operational and licensed by 2030. Our micro", "item7": "ITEM 7. Management’s Discussion and Analysis of Financial Condition and Results of Operations The following discussion should be read in conjunction with our consolidated financial statements and the related notes contained elsewhere in this Report and in our other Securities and Exchange Commission filings. The following discussion may contain predictions, estimates, and other forward-looking statements that involve a number of risks and uncertainties, including those discussed under “Risk Factors” and elsewhere in this Report. These risks could cause our actual results to differ materially from any future performance suggested below. Overview We are a nuclear energy and technology company, developing smaller, simpler, and safer advanced clean energy solutions, utilizing proprietary reactor designs, intellectual property, and research methods, to contribute towards a sustainable future. Led by a world class scientific and management team, our business plan involves comprehensive engagement across all sectors of the nuclear power and energy industry, spanning the value chain from sourcing raw materials to the development of cutting-edge advanced nuclear microreactors. Our dedication extends further, encompassing strategic initiatives within the commercial nuclear fuel transportation sector, the nuclear energy fuel supply chain, technology development, and nuclear consulting services. Currently, we are in the pre-revenue stage and are principally focused on four business lines as part of our development strategy, including our micro nuclear reactor business, our nuclear fuel processing business, our nuclear fuel transportation business, and our nuclear consultation services business. Our mission is to become a commercially focused, diversified and vertically integrated nuclear energy company that will capture market share in the very large and growing nuclear energy sector. To implement our plans, since our founding in 2022, our management has had constant communications with key U.S. government agencies, including the DOE, the INL and ORNL, which are a part of the DOE’s national nuclear laboratory system. Our company also maintains important collaborations with leading researchers from the Cambridge Nuclear Energy Centre and The University of California, Berkeley. 57 Overview of Operational Plan and Estimated Timelines for Corporate Achievements We continue to benefit from a global nuclear energy renaissance driven by several long term, sustainable growth trends and significant regulatory tailwinds. These include growth in AI data centers, industrial reshoring, and broader electrification, all driving a significant need for clean and reliable power, energy sustainability and independence, and climate mandates requiring reliable zero-emissions energy. All of this comes in an era of unprecedented bipartisan legislative and policy support in the U.S. for nuclear energy. Equally important, there is broad recognition that advanced reactors like the ones we are developing will be critical to future clean energy infrastructure. Over the next twelve months, we will continue to progress the development of our advanced reactors and our vertically integrated business plan, with estimated expenditures to be approximately $65 million. This allocation comprises approximately $43 million dedicated to the research, development, quality assurance, licensing, and physical test work of our microreactors and other technologies, such as our ALIP technology and fuel transportation system. A further amount of approximately $12 million will be allocated to the development of our planned HALEU fuel processing facilities alongside LIST, the related-party uranium enrichment company with whom we collaborate and in which we have made a strategic investment. The remaining approximately $10 million is earmarked for miscellaneous costs essential to propelling the progress of our microreactors, encompassing the support of current personnel engaged in executive, finance, accounting, and other administrative functions. We may also utilize our cash resources raised in 2024 and 2025 for acquisitions of complementary businesses or assets. As such, and for a variety of other factors, our estimated expenditures may differ substantially from the above estimates and we find it desirable or necessary to utilize cash resources faster than we currently plan. In early April 2025, we signed a strategic collaboration with UIUC to construct the first KRONOS MMR™ research reactor on the university’s campus. In mid-April 2025, we launched a recruitment initiative focused on the Midwest region to support our plans to construct, demonstrate and gain regulatory approval for full-scale KRONOS MMR ™ in both the United States and Canada. In late April 2025, the NRC issued its final Safety Evaluation (SE) approving the Fuel Qualification Methodology Topical Report (FQM TR) for the advanced fuel design to be used in our KRONOS MMR™. In July 2025, we announced that "}','deep_research','2025-12-18','2026-06-14T00:04:29');
INSERT INTO company_profiles VALUES('SMR','NuScale Power是全球唯一获NRC(美国核管会)设计认证的SMR(小型模块化反应堆)公司。VOYGR设计每个模块77 MWe，6模块组成462 MWe电站。不建造/运营电站——授权设计+提供工程服务。旗舰CFPP项目2023年取消。Q1 2026收入仅$57万。市值$32-43亿(波动大)。','["VOYGR-6 SMR设计(462 MWe) — NRC认证", "ENTRA1数据中心专用设计", "工程/许可/咨询服务", "不制造/不运营——纯设计授权模式"]','NRC设计认证是唯一护城河，但正在被追赶: TerraPower Natrium(2026.3获NRC建设许可)/GE-Hitachi BWRX-300(加拿大Darlington部署)/Kairos Power(Google签PPA)/X-energy(DOE资助)。CFPP取消严重损害信誉。','1. 唯一NRC标准设计批准(2020原始/2025升级) 2. 轻水堆技术(最成熟的反应堆类型)——监管风险最低 3. 但: CFPP取消暴露了成本问题(从$58→$89/MWh) 4. 罗马尼亚项目是验证经济性的唯一机会','["罗马尼亚Nuclearelectrica(最先进项目)", "Standard Power(数据中心,早期)", "韩国/哈萨克斯坦(MOU,未实质化)", "无超大客户(微软/谷歌/亚马逊)签约"]','["Fluor Corporation(工程/建造伙伴)", "HALEU不需要——轻水堆用标准LEU"]','1. CFPP取消——旗舰项目失败，成本超支暴露经济性问题 2. Q1收入$57万——基本零商业收入 3. TerraPower已获NRC建设许可——追赶者动真格 4. 罗马尼亚项目failure=对公司致命 5. $32-43亿市值买纸面设计 6. 28%裁员(2024初)后团队稳定性存疑','全球SMR市场长期巨大(AI核电化驱动)。但NuScale目前无确定份额——0台运行反应堆。','{"item1": "Item 1. Business Unless the context otherwise requires, all references in this section to “NuScale,” the “Company,” “we,” “us” or “our” refer to the consolidated operations of NuScale Corp and NuScale LLC. Overview NuScale is redefining nuclear power through the development of proprietary and innovative SMR technology that the Company believes will deliver safe, scalable, cost-effective and reliable carbon-free power. The Company’s core technology, the Light Water Nuclear Reactor NuScale Power Module™ (“NPM”), can generate 77 MWe and is premised on well-established nuclear technology principles, with a focus on the integration of components, simplification or elimination of systems and use of passive safety features. The Company believes this results in a safe and highly reliable power plant suitable to be sited close to where electricity, water desalinization, hydrogen production or process heat is needed. Since 2007, over $1.8 billion has been invested in the development of NuScale technology, including more than $578.3 million from DOE under a series of cost-share programs, and we have received 513 patents globally, with an additional 268 patent applications currently pending. In September 2020, the Company’s 12-module design (currently approved for 160 million watts of thermal power or 50 MWe per NPM) became the first and only SMR to receive an SDA from the Nuclear Regulatory Commission (“NRC”). In the U.S., the NRC oversees the licensing, permitting, and decommissioning of nuclear sites. In May 2025, the NRC finalized their review and approved the Company’s second SDA application and the associated licensing topical reports for NuScale’s 6-unit 77 MWe NPM design. Customers in the United States are now able to reference the approved design and SDA for expedited construction and operating licensing for a plant that is using the NuScale SMR technology. NuScale’s unique SMR has several key defining characteristics, including: • Proven. The Company’s NPM technology leverages existing light water nuclear reactor technology and conventional low-enriched uranium fuel supply that have been operating globally for over 60 years. • Simple. NuScale’s simple NPM design, based on natural circulation, integrates the reactor core, steam generators and pressurizer in a single factory-built vessel and eliminates the need for reactor coolant circulating pumps, large bore piping and other components found in conventional large-scale nuclear reactors. This simplicity improves safety and reduces capital and operational costs. • Scalable . The NPMs allow for scalability from one to twelve modules in a single installation, with typical scales of 12-module (924 MWe), six-module (462 MWe) and four-module (308 MWe) versions. These NuScale SMR-based configurations can commence operation with one module and scale to house up to their approved capacity of four, six or twelve modules. This scalability is expected to allow customers to right-size their up-front capital investment and economically increase installed capacity over time through the addition of NPMs. • Safe . NuScale believes that its SMR technology design is the safest in the world for nuclear plants and that it has several industry-first advantages over conventional large-scale nuclear plants, including an unlimited “coping” period during which the NPMs can be shut down and kept in a safe condition without operator intervention, AC or DC power or any additional cooling water. As a result, the Company believes it has numerous operational and commercial advantages including a safety case that supports a small, site-boundary emergency planning zone (“EPZ”) designation by the NRC, as well as various resiliency and reliability features including the ability to start and operate a plant without AC or DC power to provide first-responder power. In addition to the sale of NPMs, we will offer a diversified suite of services throughout the development and operating life of the power plant. The Company’s suite of services is planned to include licensing support, testing, training, fuel supply services and program management, among others. We anticipate that the Company’s service offerings will have high penetration rates across the customer base and will provide consistent, recurring revenues throughout the project deployment phase and operating lives of NPMs. We expect service revenue to begin approximately five years prior to a power plant’s commercial operation date and to extend throughout the life of the power plant. Potential offtake customers are a mix of domestic and international governments, utilities, state-owned enterprises and technology and industrial companies in need of carbon-free, reliable energy. As discussed in the section titled “Supply Chain and Partners”, we benefit from a global network of supply chain partners that we expect will play an integral role in bringing NuScale’s technology to market around the world, including 1 engineering, procurement, design a", "item1a": "Item 1A. Risk Factors We have identified the following risks and uncertainties that may have a material adverse effect on our business, financial condition, results of operations or reputation. The risks described below are not the only risks we face. Additional risks not presently known to us or that we currently believe are not material may also significantly affect our business, financial condition, results of operations or reputation. Our business could be harmed by any of these risks. In assessing these risks, you should also refer to the financial statements and related notes contained in this report. Risks Related to Our Structure and Tax Matters NuScale Corp is a holding company and its only material asset is its interest in NuScale LLC, and it is accordingly dependent upon distributions made by its subsidiaries to pay taxes, make payments under the Tax Receivable Agreement and pay dividends and fees associated with being a public company such as director retainers, NYSE and other regulatory filings. NuScale Corp is a holding company with no material assets other than its ownership of NuScale LLC units. As a result, NuScale Corp has no independent means of generating revenue or cash flow. NuScale Corp’s ability to pay taxes, cause NuScale LLC to make payments under the Tax Receivable Agreement and pay dividends depends on the financial results and cash flows of NuScale LLC and the distributions it receives (directly or indirectly) from NuScale LLC. Deterioration in the financial condition, earnings or cash flow of NuScale LLC for any reason could limit or impair its ability to pay such distributions. Additionally, to the extent that NuScale Corp needs funds and NuScale LLC is restricted from making such distributions under applicable law or regulation, in order to satisfy certain obligations, under the terms of any financing arrangements, or is otherwise unable to provide such funds, it could materially adversely affect NuScale Corp’s liquidity and financial condition. NuScale LLC is treated as a partnership for United States federal income tax purposes and, as such, generally will not be subject to any entity-level United States federal income tax. Instead, taxable income will be allocated to holders of NuScale LLC units. Accordingly, NuScale Corp will be required to pay income taxes on its allocable share of any net taxable income from NuScale LLC. Under the terms of the Sixth Amended and Restated Limited Liability Company Agreement of NuScale LLC (the “A&R NuScale LLC Agreement”), NuScale LLC is obligated to make tax distributions to holders of NuScale LLC units calculated at certain assumed tax rates. In addition to income taxes, NuScale Corp is also expected to incur expenses related to its operations, including payment obligations under the Tax Receivable Agreement, which could be significant, and some of which will be reimbursed by NuScale LLC (excluding payment obligations under the Tax Receivable Agreement). NuScale Corp intends to cause NuScale LLC to make ordinary distributions and tax distributions to holders of NuScale LLC units on a pro rata basis in amounts sufficient to cover all applicable taxes, relevant operating expenses, payments under the Tax Receivable Agreement and dividends, if any, declared by NuScale Corp. However, as discussed above, NuScale LLC’s ability to make such distributions may be subject to various limitations and restrictions. To the extent that NuScale Corp is unable to make payments under the Tax Receivable Agreement for any reason, such payments will be deferred and will accrue interest until paid; provided, however, that nonpayment for a specified period may constitute a breach of a material obligation under the Tax Receivable Agreement and therefore accelerate payments under the Tax Receivable Agreement, which could be substantial. Additionally, although NuScale LLC generally will not be subject to any entity-level United States federal income tax, it may be liable under recent United States federal tax legislation for adjustments to prior year tax returns, absent an election to the contrary. In the event NuScale LLC’s calculations of taxable income are incorrect, NuScale LLC and its members, including NuScale Corp, in later years may be subject to material liabilities pursuant to this legislation and its related guidance. If NuScale LLC were treated as a corporation for United States federal income tax or state tax purposes, then the amount available for distribution by NuScale LLC could be substantially reduced and the value of NuScale Corp shares could be adversely affected. An entity that would otherwise be classified as a partnership for United States federal income tax purposes (such as NuScale LLC) may nonetheless be treated as, and taxable as, a corporation if it is a “publicly traded partnership” unless an exception to such treatment applies. An entity will be treated as a “publicly traded partnership” if interests in such entity are traded on an e", "item7": "Item 7. Management’s Discussion and Analysis of Financial Condition and Results of Operations The following discussion and analysis of the financial condition and results of operations should be read together with our financial statements as of and for the years ended December 31, 2025, 2024 and 2023 together with related notes thereto. This discussion may contain forward-looking statements based upon current expectations that involve risks and uncertainties, including, but not limited to, those described under the section entitled “Risk Factors” included in this Form 10-K. Our actual results may differ materially from those projected in these forward-looking statements as a result of various factors. As used herein, “NuScale,” the “Company,” “us,” “our” or “we” refer to NuScale Corp, together with its consolidated subsidiaries. Overview Our mission is to provide scalable advanced nuclear technology to produce electricity, heat and clean water to improve the quality of life for people around the world. We are commercializing a modular, scalable electric Light Water Reactor nuclear power plant, that we believe will deliver safer scalable, cost-effective and reliable carbon free power. Our core technology, the NPM, can generate 77 MWe, with a focus on the integration of components, simplification or elimination of systems and use of passive safety features. We believe that this results in a safe and highly reliable power plant suitable to be sited close to where electricity, water desalinization, hydrogen production or process heat is needed. Since our founding in 2007, we have made significant progress towards commercializing the first SMR in the United States. In September 2020, our 12-module design (currently approved for 160 million watts of thermal power or 50 MWe per NPM) became the first and only SMR to receive an SDA from the NRC. In May 2025, the NRC finalized their review and approved our second SDA application and the associated licensing topical reports for our 6-unit 77 MWe NPM design, giving customers in the United States the ability to reference the approved design and SDA for expedited construction and operating licensing for a plant that is using the NuScale SMR technology. Outlook NuScale has contracted with ENTRA1 as our global strategic partner for commercialization and development of power plants utilizing NPMs. ENTRA1 holds the exclusive rights for the worldwide commercialization, distribution, sales and development of our products, services and power plants. In this strategic partnership, the Company collaborates on joint development initiatives and financially contributes alongside the partnership in joint activities which may be recoverable as part of its development costs. ENTRA1 can decide whether to participate in a commercial opportunity. If ENTRA1 declines to participate in a commercial opportunity, NuScale may pursue the opportunity on its own. Foreign SMR Market Demand for energy in foreign markets is currently being driven by population growth, industrialization and urbanization with countries in Asia contributing the most to international growth. Rising living standards, driven by economic growth, has increased the need for residential electricity, a trend that is expected to increase in the coming years, with Asia forecasted to account for nearly 60% of global growth in electricity consumption through 2050. The Company has currently one international customer: RoPower Nuclear S.A. (“RoPower”), which is a joint venture established by S.N. Nuclearelectrica S.A. (“Nuclearelectrica”) and Nova Power & Gas S.A. In July 2024, NuScale and RoPower signed a technology licensing agreement, which granted RoPower a right to use certain intellectual property of NuScale’s. In the third quarter of the 2024 fiscal year, Nuclearelectrica and RoPower signed the Front-End Engineering and Design (“FEED”) Phase 2 contract with Fluor, a related party to NuScale. FEED Phase 2 included tasks related to the development of a Class 3 plant cost estimate, as well as support to RoPower with its regulatory and stakeholder engagements. NuScale completed their scope of FEED Phase 2 as a subcontractor to Fluor. On February 12, 2026 the Romanian Government approved the investment decision for the Doicesti SMR plant project, allowing for the ability to seek secured financing to further feasibility studies, and site-specific design work prior to any construction moving forward. This is a positive step in support of the project to the next phase. During the coming months, RoPower is authorized to advance the licensing and geotechnical work, finalize a pre-engineering, procurement and construction (“EPC”) contract, and begin negotiating contracts for long lead items. We anticipate that the pre-EPC activities will have an estimated duration of up to 15 months and will include, among other things, the development of a Class 2 cost estimate for the project. NuScale has yet to commence, but looks forward to negotiati"}','deep_research','2026-02-26','2026-06-14T00:04:29');
INSERT INTO company_profiles VALUES('WLDN','Willdan Group是美国能源效率项目管理和市政工程服务公司。两个业务: 能源(~80-85%收入,为公用事业设计/管理能效项目)和工程咨询(~15-20%,市政基础设施)。FY2025收入$6.82亿(+20% YoY)。市值$14.7亿。26x P/E。','["公用事业能效项目管理(核心) — 设计/管理节能方案", "需求响应/负荷管理", "可持续发展咨询", "市政工程 — 给排水/交通/建筑", "法规合规服务"]','竞争性投标市场——与ICF International/CLEAResult/Franklin Energy/Guidehouse竞争公用事业合同。非寡头/垄断。转换成本存在(项目连续性)但非结构性壁垒。电网互联真正瓶颈在高压变电站/输电线路工程(Burns & McDonnell/Black & Veatch)——WLDN做的是需求侧管理非供给侧建设。','无显著技术壁垒——项目管理/工程咨询是人力密集型服务。壁垒在于长期客户关系、加州市场深耕、合规认证。但不构成Serenity瓶颈。','["加州公用事业公司(PG&E/SCE等) — 核心客户", "其他州公用事业", "地方政府(市政工程)", "联邦机构"]','["人力资源(工程师/项目经理) — 主要成本", "无供应链依赖"]','1. 竞争性投标——替代供应商多 2. 加州公用事业预算依赖监管(政策风险) 3. 项目制收入波动(合同到期再投标) 4. 与AI关联为间接受益非直接链条 5. 26x P/E已price-in增长——上行空间有限','美国公用事业能效项目市场数十亿美元级别。数据中心电网压力长期驱动公用事业需求管理预算增长——但WLDN是受益者非瓶颈。','{"item1": "Item 1. Business—Available Information.” To the extent required by rules adopted by the SEC and the Nasdaq Stock Market, we intend to promptly disclose future amendments to certain provisions of the code, or waivers of such provisions granted to executive officers and directors on our website at www.willdan.com under “Investors—Governance.” ​ ITEM 11. EXECUTIVE COMPENSATION The information required by this item is incorporated by reference to Willdan Group, Inc.’s Proxy Statement for its 2026 Annual Meeting of Stockholders to be filed with the SEC within 120 days after the end of the Company’s 2025 fiscal year. ITEM 12. SECURITY OWNERSHIP OF CERTAIN BENEFICIAL OWNERS AND MANAGEMENT AND RELATED SHAREHOLDER MATTERS The information required by this item is incorporated by reference to Willdan Group, Inc.’s Proxy Statement for its 2026 Annual Meeting of Stockholders to be filed with the SEC within 120 days after the end of the Company’s 2025 fiscal year. ​ ITEM 13. CERTAIN RELATIONSHIPS AND RELATED TRANSACTIONS, AND DIRECTOR INDEPENDENCE The information required by this item is incorporated by reference to Willdan Group, Inc.’s Proxy Statement for its 2026 Annual Meeting of Stockholders to be filed with the SEC within 120 days after the end of the Company’s 2025 fiscal year. ​ ITEM 14. PRINCIPAL ACCOUNT ING FEES AND SERVICES The information required by this item is incorporated by reference to Willdan Group, Inc.’s Proxy Statement for its 2026 Annual Meeting of Stockholders to be filed with the SEC within 120 days after the end of the Company’s 2025 fiscal year. ​ 110 Table of Contents ​ PART I V ITEM 15. EXHIBITS , FINANCIAL STATEMENT SCHEDULES (a) The following documents are filed as part of this report: 1. Financial Statements The financial statements included in Part II, Item 8 of this document are filed as part of this Annual Report on Form 10-K. 2. Financial Statements Schedules All required schedules are omitted because they are not applicable or the required information is shown in the financial statements or the accompanying notes. 3. Exhibits The exhibits filed as part of this annual report are listed in Item 15(b). (b) Exhibits. The following exhibits are filed as a part of this report: ​ Exhibit Number ​ Exhibit Description 2.1‡ ​ Stock Purchase Agreement, dated as of March 3, 2025, by and among Willdan Group, Inc., Willdan Energy Solutions, Inc. and each of the stockholders of APG. (incorporated by reference to Exhibit 2.1 to Willdan Group, Inc.’s Quarterly Report on Form 10-Q, filed with the SEC on May 9, 2025). 3.1 ​ First Amended and Restated Certificate of Incorporation of Willdan Group, Inc. (incorporated by reference to Willdan Group, Inc.’s Registration Statement on Form S-1, filed with the SEC on August 9, 2006, as amended (File No. 333-136444)) . 3.2 ​ Second Amended and Restated Bylaws of Willdan Group, Inc. (incorporated by reference to Exhibit 3.1 to Willdan Group, Inc.’s Current Report on Form 8-K, filed with the SEC on July 12, 2023). 4.1 ​ Specimen Stock Certificate for shares of the Registrant’s Common Stock (incorporated by reference to Willdan Group, Inc.’s Registration Statement on Form S-1, filed with the SEC on August 9, 2006, as amended (File No. 333-136444)) . 4.2* ​ Description of Willdan Group, Inc.’s Capital Stock. 4.3 ​ The Company agrees to furnish to the Securities and Exchange Commission upon request a copy of each instrument with respect to issues of long-term debt of Willdan Group, Inc. and its subsidiaries, the authorized principal amount of which does not exceed 10% of the consolidated assets of Willdan Group, Inc. and its subsidiaries. 10.1 ​ Amended and Restated Credit Agreement, dated as of May 5, 2025, by and among Willdan Group, Inc., as Borrower, the Guarantors (as defined therein), the Lenders (as defined therein), BMO Bank N.A., as Joint Lead Arranger, Joint Book Runner and Administrative Agent, Bank of America, N.A. as Joint Book Runner and Syndication Agent and J.P. Morgan, N.A. as Joint Lead Arranger, Joint Book Runner and Syndication Agent (incorporated by reference to Exhibit 10.1 to Willdan Group, Inc.’s Quarterly Report on Form 10-Q, filed with the SEC on May 9, 2025). 111 Table of Contents ​ Exhibit Number ​ Exhibit Description 10.2 ​ The Security Agreement, dated as of September 29, 2023, by and among Willdan Group, Inc., as Borrower, the Debtors (as defined therein), and BMO Bank N.A., as Administrative Agent (incorporated by reference to Exhibit 10.2 to Willdan Group, Inc.’s Current Report on Form 8-K, filed with the SEC on October 5, 2023). 10.3† ​ Form of Performance Based Restricted Stock Unit Award Agreement (pre-2024) (incorporated by reference to Exhibit 10.15 to Willdan Group, Inc.’s Annual Report on Form 10-K filed on March 10, 2023). 10.4† ​ Form of Restricted Stock Award Agreement (pre-2024) (incorporated by reference to Exhibit 10.16 to Willdan Group, Inc.’s Annual Report on Form 10-K filed on March 10, 2023). 10.5† ​ Form of Performan", "item1a": "Item 1A. Risk Factors in this Annual Report on Form 10-K, “ Cyber security breaches or other systems and information technology interruptions could result in liability, harm our reputation, impact our ability to operate, and other material adverse consequences.” The Company engages third-party cybersecurity consultants and auditors who help the cybersecurity team in identifying, assessing, and managing material risks from cybersecurity threats, including by evaluating and enhancing the Company’s cybersecurity posture. The Company also engages third-party service providers to perform a variety of functions throughout its business. The Company performs due diligence before engaging with certain third-party service providers designed to evaluate the service providers’ cybersecurity practices, including their security policies, incident response capabilities, and data protection measures; including specific cybersecurity requirements in contracts with certain third-party service providers, such as regarding security standards, data protection, and incident reporting as applicable; and monitoring and auditing certain third-party service providers’ cybersecurity practices and compliance with contractual obligations. Depending on the nature of the services provided, the sensitivity of the information systems and data at issue, and the identity of the provider, the Company’s vendor management process may involve different levels of assessment designed to help identify cybersecurity risks associated with a provider and impose contractual obligations related to cybersecurity on the provider. 31 Table of Contents Governance The Board addresses the Company’s cybersecurity risk management as part of its general oversight function. The Board is responsible for overseeing Company’s cybersecurity risk management processes, including oversight and mitigation of risks from cybersecurity threats. Our cybersecurity risk assessment and management processes are implemented and maintained by the certain members of Company management , including those who are part of the Company’s cybersecurity team . The Company’s cybersecurity team is comprised of individuals with expertise in cybersecurity, information technology, risk management, and Company operations. Our cybersecurity team has decades-long experience in cybersecurity and holds industry-standard certifications including Certified Information Systems Security Professional (“CISSP”), and Certified Cloud Security Professional (“CCSP”), among others. Management is responsible for hiring appropriate personnel, helping to integrate cybersecurity risk considerations into the Company’s overall risk management strategy, and communicating key priorities to relevant personnel. Management is responsible for approving budgets, helping prepare for cybersecurity incidents, approving cybersecurity processes, and reviewing security assessments and other security-related reports. The Company’s cybersecurity incident response plan is designed to escalate certain cybersecurity incidents to members of management depending on the circumstances, including the Company’s President and Chief Executive Officer, Chief Financial Officer, and General Counsel (collectively, “Executive Management”). Executive Management works with the Company’s incident response team to help the Company mitigate and remediate cybersecurity incidents of which they are notified. In addition, the Company’s incident response plan includes reporting to the Board for certain cybersecurity incidents. The Company’s Board provides oversight of cybersecurity risk and regularly receives updates from the Company’s cybersecurity team. These updates cover topics that include cybersecurity team member updates, cybersecurity infrastructure updates, improvement in cyber-security tools and technologies, cybersecurity framework compliance, cyber-risk hardware/software enhancement updates, cybersecurity threats and mitigation measures, and more. The Board also has access to various reports, summaries or presentations related to cybersecurity threats, risk and mitigation. ​ 32 Table of Contents ITEM 2. PROPERTIES Our corporate headquarters is located at 2401 East Katella Avenue, Anaheim, California, where we lease approximately 18,000 square feet of office space. In addition, we lease office space in 48 other locations nationwide. In addition to the U.S. locations, we also have one office in Canada and one office in the Commonwealth of Puerto Rico. In total, our facilities contain approximately 224,000 square feet of office space and are subject to leases that expire through 2034. We rent a small portion of this total space on a month-to-month basis. We believe that our existing facilities are adequate to meet current requirements and that suitable additional or substitute space will be available as needed to accommodate any expansion of operations and for additional offices. ITEM 3. LEGAL PROCEEDINGS We are subject to claims and lawsuits from", "item7": "ITEM 7. MANAGEMENT’S DISCUSSION AND ANALYSIS OF FINANCIAL CONDITION AND RESULTS OF OPERATIONS Our Company We are a provider of professional, technical and consulting services to utilities, private industry, and public agencies at all levels of government. As resource and infrastructure needs undergo continuous change, we help organizations and their communities evolve and thrive by providing a wide range of technical services for energy solutions, greenhouse gas reduction, and government infrastructure. Through engineering, program management, policy advisory, and software and data analytics, we plan, design and deliver comprehensive, innovative, cost-effective, and proven solutions to improve efficiency, resiliency, and sustainability in energy and infrastructure to our clients. Our broad portfolio of services operates within two financial reporting segments: (1) Energy and (2) Engineering and Consulting. The interfaces and synergies between these segments are important elements of our strategy to design and deliver trusted, comprehensive, innovative, and proven solutions and services for our customers. Our Energy segment provides specialized, innovative, comprehensive energy solutions to businesses, utilities, state agencies, municipalities, and non-profit organizations. Our experienced engineers, consultants, and staff help our clients realize cost and energy savings by tailoring efficient and cost-effective solutions to assist in optimizing energy spend. Our energy services include comprehensive audit and surveys, program design, master planning, demand reduction, grid optimization, benchmarking analyses, design engineering, AI data center power solutions, construction management, performance contracting, installation, alternative financing, measurement and verification services, and advances in software and data analytics for long-term planning. Our Engineering and Consulting segment provides civil engineering and construction management, building and safety services, city engineering and planning support, civil design, geotechnical services, and material testing. Our capabilities span traffic, bridges, rail, port, water systems, and other major infrastructure projects. In addition to technical expertise, we provide economic and financial consulting that helps agencies plan, fund, and maintain both daily operations and long-term capital programs. We also support the mandated reporting and other requirements associated with these financings. We provide financial advisory services for municipal securities but do not provide underwriting services. ​ 37 Table of Contents Results of Operations Summary comparison of fiscal years 2025, 2024, and 2023 The following table sets forth, for the periods indicated, certain information derived from our consolidated statements of comprehensive income (1) : ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ Fiscal Year ​ ​ 2025 ​ 2024 ​ 2023 ​ ​ (in thousands, except percentages) Contract revenue ​ $ 681,552 ​ 100.0 % ​ $ 565,798 ​ 100.0 % ​ $ 510,095 ​ 100.0 % Direct costs of contract revenue: ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ Salaries and wages ​ ​ 109,098 ​ 16.0 ​ ​ ​ 93,543 ​ 16.5 ​ ​ ​ 89,915 ​ 17.6 ​ Subcontractor services and other direct costs ​ ​ 316,772 ​ 46.5 ​ ​ ​ 269,473 ​ 47.6 ​ ​ ​ 240,413 ​ 47.1 ​ Total direct costs of contract revenue ​ ​ 425,870 ​ 62.5 ​ ​ ​ 363,016 ​ 64.2 ​ ​ ​ 330,328 ​ 64.8 ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ Gross profit ​ ​ 255,682 ​ 37.5 ​ ​ ​ 202,782 ​ 35.8 ​ ​ ​ 179,767 ​ 35.2 ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ General and administrative expenses: ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ Salaries and wages, payroll taxes and employee benefits ​ ​ 125,736 ​ 18.4 ​ ​ ​ 105,373 ​ 18.6 ​ ​ ​ 95,556 ​ 18.7 ​ Facilities and facilities related ​ ​ 9,717 ​ 1.4 ​ ​ ​ 9,718 ​ 1.7 ​ ​ ​ 9,565 ​ 1.9 ​ Stock-based compensation ​ ​ 11,825 ​ 1.7 ​ ​ ​ 7,388 ​ 1.3 ​ ​ ​ 5,323 ​ 1.0 ​ Depreciation and amortization ​ ​ 18,686 ​ 2.7 ​ ​ ​ 14,745 ​ 2.6 ​ ​ ​ 16,431 ​ 3.2 ​ Other ​ ​ 45,571 ​ 6.7 ​ ​ ​ 34,205 ​ 6.0 ​ ​ ​ 30,818 ​ 6.0 ​ Total general and administrative expenses ​ ​ 211,535 ​ 31.0 ​ ​ ​ 171,429 ​ 30.3 ​ ​ ​ 157,693 ​ 30.9 ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ Income (loss) from operations ​ ​ 44,147 ​ 6.5 ​ ​ ​ 31,353 ​ 5.5 ​ ​ ​ 22,074 ​ 4.3 ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ Other income (expense): ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ Interest expense ​ ​ (5,748) ​ (0.8) ​ ​ ​ (7,801) ​ (1.4) ​ ​ ​ (9,413) ​ (1.8) ​ Other, net ​ ​ 1,595 ​ 0.2 ​ ​ ​ 3,127 ​ 0.6 ​ ​ ​ 1,930 ​ 0.4 ​ Total other income (expense) ​ ​ (4,153) ​ (0.6) ​ ​ ​ (4,674) ​ (0.8) ​ ​ ​ (7,483) ​ (1.5) ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ ​ Income (Loss) before income tax expense ​ ​ 39,994 ​ 5.9 ​ ​ ​ 26,679 ​ 4.7 ​ ​ ​ 14,591 ​ 2.9 ​ Income tax expense (benefit) ​ ​ (12,563) ​ (1.8) ​ ​ ​ 4,109 ​ 0.7 ​ ​ ​ 3,665 ​ 0.7 ​ Net income (loss) ​ $ 52,557 ​ 7.7 ​ ​ $ 22,570 ​ 4.0 ​ ​ $ 10,926 ​ 2.1 ​ ​ (1) Percentages are expressed as a percentage of contract rev"}','deep_research','2026-02-27','2026-06-14T00:04:29');
INSERT INTO company_profiles VALUES('CAMT','Camtek是以色列先进封装自动光学检测(AOI)和计量设备领导者。专注2D晶圆检测(表面缺陷/图案异常)和3D计量(凸块高度/共面性/TSV深度)。覆盖CoWoS、HBM堆叠、扇出型封装、Chiplet集成等先进封装流程。市值~$89亿。','["2D图案晶圆检测 — 后光刻/RDL/微凸块检测", "3D计量 — 凸块高度、共面性、TSV深度测量", "混合键合对准验证", "AI增强缺陷分类(Visual Layer收购)", "晶圆级封装最终QC"]','先进封装检测专精厂商，相比KLA($5-10M/台)价格更低，是OSAT和后端产线的首选。KLA在广义光学检测占89.9%份额，但CAMT在先进封装细分领域有成本/灵活性优势。竞争者还包括Onto Innovation和Applied Materials。','1. 先进封装细分专精——目的性设计，而非KLA的通用方案降维使用 2. 2D+3D组合检测能力——单次扫描完成多维测量 3. Visual Layer AI收购——深度学习缺陷分类 4. 多年台积电/三星/英特尔认证供应商资质','["台积电(CoWoS/SoIC检测)", "三星(HBM/先进封装)", "英特尔(Foveros)", "主要OSAT(ASE/Amkor)", "Q1 FY26收入$1.22亿"]','["以色列本土研发制造", "资产轻模型(组装非制造)", "交付周期3-6个月"]','1. KLA若低价进入先进封装检测将直接威胁CAMT 2. 客户集中度高(台积电+几家内存厂占大头) 3. 222x trailing P/E估值极端，Forward P/E ~55x 4. 以色列地缘政治风险 5. 31%空头比例——市场分歧大','先进封装检测市场随HBM/CoWoS扩张结构性增长。HBM从8-hi到16-hi，检测步骤近似翻倍。台积电CoWoS目标30-40K片/月(SoIC)。',NULL,'deep_research',NULL,'2026-06-14T00:04:29');
INSERT INTO company_profiles VALUES('HYNIX','SK海力士是全球HBM(高带宽内存)绝对霸主，58%市场份额。2026 Q1营业利润率72%(历史新高)。NVIDIA公开宣布的第一内存合作伙伴。HBM3/3E/4每一代均首发量产。市值突破万亿美元。2026年8月计划NASDAQ ADR上市。','["HBM3E — 当前量产主力，占HBM出货~2/3", "HBM4 — 全球首家量产(2025.9)，Vera Rubin 60-70%分配", "DDR5 — 服务器内存", "LPDDR5X — 移动设备", "NAND — 闪存(较低利润率)"]','三家寡头: SK海力士58%/三星21%/美光21%。三星因良率问题掉到第三。海力士每一代HBM都首发量产——HBM3(2023)→HBM3E(2024)→HBM4(2025)。NVIDIA Jensen Huang 2026.6.8公开确认SK海力士为第一供应商。','1. MR-MUF(模塑底填)专有封装技术——良率领先于三星的混合键合方案 2. HBM每一代首发量产的一致性记录 3. 与NVIDIA深度共同设计(iHBM下一代) 4. TSMC CoWoS深度协作 5. 多年供应协议锁定定价框架','["NVIDIA(第一内存合作伙伴，Jensen亲口确认)", "AMD", "超大规模云厂商"]','["自有晶圆厂(韩国利川/清州/中国无锡)", "无锡工厂=50%总DRAM产能(地缘风险)", "设备: ASML/应用材料等"]','1. 三星HBM4已获NVIDIA认证——竞争将加剧 2. DRAM历史性boom-bust周期 3. 中国CXMT崛起(8%常规DRAM份额) 4. 无锡工厂50%产能——地缘政治脆弱性 5. 股价12个月涨900%+——估值和情绪极度拉伸 6. HBM价格6倍涨幅可能见顶(摩根士丹利警告)','HBM市场2025年~$250亿，2027年预计翻倍。每代GPU HBM含量倍增: H100=80GB→Rubin Ultra=512GB。',NULL,'deep_research',NULL,'2026-06-14T00:04:29');
INSERT INTO company_profiles VALUES('GSM','Ferroglobe是西方最大硅金属生产商，同时生产硅铁合金和锰合金。工厂在西班牙/法国/美国/南非/加拿大。硅金属用于铝合金/有机硅/太阳能多晶硅/钢铁。市值~$7.6亿。当前亏损(EPS -$0.60)。与AI/半导体的连接极其间接(距芯片4步加工)。','["硅金属(~45%收入) — 铝合金/多晶硅/有机硅原料", "硅铁合金(~35%收入) — 炼钢添加剂", "锰合金(~20%收入) — 炼钢", "石英矿(西班牙/美国/加拿大/南非)", "法国水电站"]','西方最大硅金属生产商，但全球75-80%产能在中国。西方竞争者: Elkem(挪威)/Wacker(德国)/Mississippi Silicon(美国)/REC Silicon。高度大宗商品化市场——无定价权、无差异化。','无技术壁垒——石英还原为硅是19世纪化学反应。壁垒仅在于能源成本(冶炼极耗电,11-13 MWh/吨)和矿产资源。法国水电提供部分能源成本优势，但不构成技术护城河。','["铝合金厂商", "有机硅化工厂", "多晶硅生产商(信越/Wacker间接)", "钢铁厂"]','["石英矿(自有)", "电力(高比例成本)", "碳还原剂"]','1. 大宗商品周期性——2021-22年暴涨后暴跌 2. 中国控制75-80%产能可随时倾销 3. 距AI供应链4步之遥——主题连接极其勉强 4. 当前亏损(EPS -$0.60) 5. 欧洲能源成本结构性劣势 6. 30x Forward P/E对大宗商品公司偏贵','全球硅金属市场约$100-120亿/年。与AI的关联是间接的多层传导——不是直接可寻址市场。',NULL,'deep_research',NULL,'2026-06-14T00:04:29');
INSERT INTO company_profiles VALUES('ALAB','Astera Labs是AI数据中心连接芯片龙头，PCIe/CXL retimer 60-70%市场份额。三大产品: Aries(PCIe/CXL retimer信号调理)、Leo(CXL智能内存控制器)、Scorpio(以太网/UALink交换机)。FY2025收入$8.53亿(+115% YoY)。毛利率76%。市值~$630亿。2024年IPO。','["Aries PCIe/CXL Retimer — 主营,恢复Gen5/Gen6高速信号完整性", "Leo CXL智能内存控制器 — 微软Azure已部署CXL内存扩展", "Scorpio以太网/UALink交换机 — H2 2026量产,TAM $200亿(2030)", "Cosmos平台 — 舰队管理软件/固件生态"]','PCIe retimer 3方寡头: ALAB(60-70%领先)/Broadcom(追赶中)/Marvell(Alaska P新进)。ALAB纯专注连接芯片,迭代速度快于Broadcom(hundreds of product lines)。但Scorpio进入以太网交换机市场直面Broadcom网络霸主地位——风险更大。','1. Gen5/Gen6 retimer首家量产——先发认证优势 2. 纯专注连接=比Broadcom迭代更快 3. 多协议统一架构(PCIe+CXL+Ethernet+UALink) 4. Cosmos平台软件锁定 5. 认证周期12-18月创造转换成本','["NVIDIA(GPU服务器需要retimer)", "Amazon(战略关系+购买权证)", "微软Azure(Leo CXL内存已部署)", "超大规模云厂商(Top客户可能>70%收入)"]','["Fabless模式,委托TSMC代工", "先进制程(5nm/3nm)"]','1. Broadcom Gen6 retimer追赶+可捆绑网络/ASIC 2. Marvell Alaska P新进(3方竞争) 3. NVIDIA NVLink绕过PCIe可能减少retimer用量 4. 125x Fwd P/E极端估值 5. Scorpio进入Broadcom网络腹地 6. 毛利率因Scorpio硬件(低利润)混合下降','PCIe retimer+CXL控制器+AI交换机TAM合计数百亿美元(Scorpio TAM $200亿 by 2030)。',NULL,'deep_research',NULL,'2026-06-14T00:29:09');
INSERT INTO company_profiles VALUES('UCTT','Ultra Clean Holdings是半导体设备气体/流体交付子系统双寡头之一(另一家ICHR)。Products部门(~75-80%收入)为Lam Research/Applied Materials等OEM制造关键子系统；Services部门(~20-25%)直接为晶圆厂提供精密清洗/涂层服务。FY2025收入~$20.5亿。市值~$45-49亿。','["气体交付系统 — 半导体设备OEM定制子系统", "流体/化学品交付模块", "精密焊接件/框架组件/工艺模块", "晶圆厂零件精密清洗和涂层服务(Services)", "直接服务TSMC/Intel/Micron/Samsung等晶圆厂"]','气体/流体子系统双寡头: UCTT(较大,~$20.5亿收入) + ICHR(Ichor Holdings,~$9.6亿收入)。为Lam Research和Applied Materials(全球前2大WFE OEM)最大外包子系统供应商。非标定制+污染控制要求=高认证壁垒。但16.5%毛利率说明是build-to-print模式,无真正定价权。','1. ppb级超高纯度气体/化学品交付——数十年污染控制know-how 2. Products+Services双模式(同时服务OEM和晶圆厂) 3. OEM认证锁定(12-18月重新认证+污染风险) 4. 规模+嵌入式关系——最大外包供应商 5. 但: 运营/关系壁垒,非专利/IP壁垒','["Lam Research(最大OEM客户之一)", "Applied Materials(最大OEM客户之一)", "TSMC/Intel/Micron/Samsung(Services直接服务)", "两家OEM可能占Products收入>60%"]','["特种金属/合金", "超高纯度管道/阀门组件", "精密焊接设备"]','1. 极端周期性——FY2025营业利润率-5.28% 2. 客户集中(Lam+AMAT可能>60%收入) 3. 16.5%毛利率=build-to-print无定价权 4. ICHR直接竞争 5. CFO近期卖出股票 6. 估值已涨230% YTD(34-39x Fwd P/E)','全球WFE(晶圆厂设备)市场~$1000亿+(2025)→$1450亿(2026)→$1560亿(2027)。UCTT可寻址市场为OEM外包子系统+晶圆厂零件服务。',NULL,'deep_research',NULL,'2026-06-14T00:29:09');
